                       <span className="text-[9px] font-black uppercase text-zinc-600 tracking-tighter">{label}</span>
                       <div className="relative w-12 h-12 rounded-full overflow-hidden border-2 border-white/10 shadow-2xl group cursor-pointer">
                         <input type="color" value={newPaletteData.colors[idx]} onChange={(e) => { const nextColors = [...(newPaletteData.colors)]; nextColors[idx] = e.target.value; setNewPaletteData({ ...newPaletteData, colors: nextColors }); }} className="absolute inset-[-10px] w-[150%] h-[150%] cursor-pointer p-0 m-0 border-none bg-transparent" />
                         <div className="absolute inset-0 pointer-events-none flex items-center justify-center opacity-0 group-hover:opacity-100 bg-black/20 transition-opacity"><Pipette size={14} className="text-white" /></div>
