flex items-center gap-2 px-1"><Sun size={14} className="text-zinc-600" /><h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Soft Ambient Light</h3></div><TransformControl label="Intensidade de Luz" value={currentSlide?.options?.postFX?.lightingIntensity ?? 0} min={0} max={1} step={0.01} onChange={(v) => updateGlobalFX('lightingIntensity', v)} /></div><div className="space-y-6 pt-6 border-t border-white/5"><div className="flex items-center gap-2 px-1"><Focus size={14} className="text-zinc-600" /><h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Global Vignette</h3></div><TransformControl label="Intensidade Vinheta" value={currentSlide?.options?.postFX?.vignette ?? 0} min={0} max={1} step={0.01} onChange={(v) => updateGlobalFX('vignette', v)} /></div></section></div>
              ) : activeTab === 'TEMPLATES' ? (
