interface ToolbarState {
  x: number;
  y: number;
  blockIndex: number;
  blockType: string;
  options: any;
}

const FloatingTextToolbar = ({ 
  state, 
  onClose, 
  onUpdate 
}: { 
  state: ToolbarState, 
  onClose: () => void, 
  onUpdate: (updates: { path: (string | number)[], value: any }[]) => void 
}) => {
  const [localFontSize, setLocalFontSize] = useState(state.options?.fontSize || 40);
  const [localSpacing, setLocalSpacing] = useState(state.options?.letterSpacing || 0);
  const [localLineHeight, setLocalLineHeight] = useState(state.options?.lineHeight || 1.2);
  const [localColor, setLocalColor] = useState(state.options?.color || '#ffffff');

  const [pos, setPos] = useState({ x: state.x - 160, y: Math.max(20, state.y - 450) });
  const [isDragging, setIsDragging] = useState(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const toolbarRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setLocalFontSize(state.options?.fontSize || 40);
    setLocalSpacing(state.options?.letterSpacing || 0);
    setLocalLineHeight(state.options?.lineHeight || 1.2);
    setLocalColor(state.options?.color || '#ffffff');
    setPos({ x: state.x - 160, y: Math.max(20, state.y - 450) });
  }, [state]);

  const onMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    dragStart.current = { x: e.clientX - pos.x, y: e.clientY - pos.y };
    e.stopPropagation();
  };

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      setPos({ x: e.clientX - dragStart.current.x, y: e.clientY - dragStart.current.y });
    };
    const onMouseUp = () => setIsDragging(false);
    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onMouseUp);
    };
  }, [isDragging]);

  const update = (key: string, val: any) => {
    onUpdate([{ path: ['blocks', state.blockIndex, 'options', key], value: val }]);
  };

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (toolbarRef.current && !toolbarRef.current.contains(event.target as Node)) {
        onClose();
      }
    };
    const timeout = setTimeout(() => {
      document.addEventListener('mousedown', handleClickOutside);
    }, 100);
    return () => {
      clearTimeout(timeout);
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [onClose]);

  return (
    <div 
      ref={toolbarRef}
      className="fixed z-[1000] bg-zinc-900/95 backdrop-blur-xl border border-white/10 rounded-[28px] shadow-2xl p-6 flex flex-col gap-6 w-80 animate-in zoom-in-95 duration-200 floating-toolbar select-none"
      style={{ top: `${pos.y}px`, left: `${pos.x}px` }}
      onClick={(e) => e.stopPropagation()}
    >
      <div 
        className="flex items-center justify-between cursor-move pb-2 border-b border-white/5 -mt-2"
        onMouseDown={onMouseDown}
      >
        <div className="flex items-center gap-2">
           <GripHorizontal size={14} className="text-zinc-600" />
           <span className="text-[9px] font-black uppercase text-zinc-500 tracking-widest">{state.blockType} Editor</span>
        </div>
        <button onClick={onClose} className="p-1 hover:bg-white/5 rounded-full text-zinc-500 hover:text-white"><X size={14}/></button>
      </div>

      <div className="grid grid-cols-1 gap-5">
        <div className="flex gap-4 items-end">
          <div className="flex-1 space-y-1">
             <TransformControl label="Font Size" value={localFontSize} min={10} max={400} step={1} onChange={(v) => { setLocalFontSize(v); update('fontSize', v); }} />
          </div>
          <div className="relative w-12 h-12 rounded-xl overflow-hidden border border-white/10 shadow-inner shrink-0">
             <input type="color" value={localColor} onChange={(e) => { setLocalColor(e.target.value); update('color', e.target.value); }} className="absolute inset-[-4px] w-[150%] h-[150%] cursor-pointer p-0 m-0 border-none" />
          </div>
        </div>

        <div className="flex gap-4">
          <TransformControl label="Letter Spacing" value={localSpacing} min={-20} max={50} step={1} onChange={(v) => { setLocalFontSize(v); update('letterSpacing', v); }} />
          <TransformControl label="Line Height" value={localLineHeight} min={0.5} max={3.0} step={0.05} onChange={(v) => { setLocalLineHeight(v); update('lineHeight', v); }} />
        </div>

        <div className="space-y-3">
           <span className="text-[9px] font-bold text-zinc-500 uppercase px-1">Tipografia do Bloco</span>
           <div className="flex bg-black/40 p-1 rounded-xl border border-white/5 gap-1">
              {[
                { id: 'padrão', label: 'Padrão' },
                { id: 'destaque', label: 'Destaque' }
              ].map(variant => (
                <button 
                  key={variant.id} 
                  onClick={() => update('fontVariant', variant.id)}
                  className={`flex-1 py-2 text-[9px] font-black uppercase rounded-lg transition-all ${state.options?.fontVariant === variant.id ? 'bg-zinc-800 text-brand' : 'text-zinc-500 hover:text-white'}`}
                >
                  {variant.label}
                </button>
              ))}
           </div>
        </div>

        <div className="space-y-1.5">
           <span className="text-[9px] font-bold text-zinc-500 uppercase px-1">Alignment</span>
           <div className="flex bg-black/40 p-1 rounded-xl border border-white/5 gap-1">
              {[
                { id: 'left', icon: AlignLeft },
                { id: 'center', icon: AlignCenter },
                { id: 'right', icon: AlignRight }
              ].map(align => (
                <button 
                  key={align.id} 
                  onClick={() => update('textAlign', align.id)}
                  className={`flex-1 py-2 flex items-center justify-center rounded-lg transition-all ${state.options?.textAlign === align.id ? 'bg-zinc-800 text-brand' : 'text-zinc-500 hover:text-white'}`}
                >
                  <align.icon size={16} />
                </button>
              ))}
           </div>
        </div>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [view, setView] = useState<'DASHBOARD' | 'EDITOR'>('DASHBOARD');
  const [activeTab, setActiveTab] = useState<'TEMPLATES' | 'BLOCKS' | 'DESIGN' | 'FX' | 'ASSETS' | 'JSON'>('TEMPLATES');

  const [projects, setProjects] = useState<Project[]>([]);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedClientFilter, setSelectedClientFilter] = useState<string | null>(null);

  const [dslInput, setDslInput] = useState(INITIAL_DSL);
  const [carousel, setCarousel] = useState<ValidatedCarousel | null>(null);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [zoom, setZoom] = useState(0.40);
  const [toast, setToast] = useState<{ message: string, type: 'success' | 'error' } | null>(null);

  const [activePaletteId, setActivePaletteId] = useState('1');
  const [brandPresets, setBrandPresets] = useState<any[]>(DEFAULT_BRAND_PRESETS);
  const [isCreatingPalette, setIsCreatingPalette] = useState(false);
  const [editingPaletteId, setEditingPaletteId] = useState<string | null>(null);
  const [newPaletteData, setNewPaletteData] = useState({
    name: '',
    colors: ['#0D0D0D', '#FFFFFF', '#EAB308', '#EAB308', '#EAB308'],
    font_padrao: 'Inter',
    font_destaque: 'Instrument Serif'
  });

  const [isUploadingFont, setIsUploadingFont] = useState(false);

  const [toolbarState, setToolbarState] = useState<ToolbarState | null>(null);
  const [isDraggingFile, setIsDraggingFile] = useState(false);

  const [showExportModal, setShowExportModal] = useState(false);
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [saveFormData, setSaveFormData] = useState({ name: '', client: '' });
  const [selectedSlidesToExport, setSelectedSlidesToExport] = useState<Set<number>>(new Set());

  const [isExporting, setIsExporting] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);
  const [exportStatus, setExportStatus] = useState('');

  const [templates] = useState<TemplateDefinition[]>(templateRegistry.getAll());

  const currentSlide = useMemo(() => carousel?.slides[currentIndex], [carousel, currentIndex]);
  const imageConfig = useMemo(() => currentSlide?.image, [currentSlide]);
  const isLocked = isExporting || isSyncing;

  const [editingIconBlock, setEditingIconBlock] = useState<{ block: Block; index: number } | null>(null);
  const [iconInput, setIconInput] = useState('');

  const canvasRef = useRef<HTMLDivElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);
  const fontInputRef = useRef<HTMLInputElement>(null);

  const showToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  }, []);

  const updateSlideProperties = useCallback((updates: { path: (string | number)[], value: any }[]) => {
    setDslInput(prev => {
      try {
        const parsed = JSON.parse(prev);
        if (!parsed.slides[currentIndex]) return prev;

        updates.forEach(({ path, value }) => {
          let target = parsed.slides[currentIndex];
          for (let i = 0; i < path.length - 1; i++) {
            const key = path[i];
            if (!target[key] || typeof target[key] !== 'object') target[key] = {};
            target = target[key];
          }
          target[path[path.length - 1]] = value;
        });

        return JSON.stringify(parsed, null, 2);
      } catch (e) {
        return prev;
      }
    });
  }, [currentIndex]);

  const updateGlobalProperty = useCallback((path: (string | number)[], value: any) => {
    setDslInput(prev => {
      try {
        const parsed = JSON.parse(prev);
        let target = parsed;
        for (let i = 0; i < path.length - 1; i++) {
          const key = path[i];
          if (!target[key] || typeof target[key] !== 'object') target[key] = {};
          target = target[key];
        }
        target[path[path.length - 1]] = value;
        return JSON.stringify(parsed, null, 2);
      } catch (e) {
        return prev;
      }
    });
  }, []);

  const updateGlobalFX = useCallback((key: string, value: any) => {
    setDslInput(prev => {
      try {
        const parsed = JSON.parse(prev);
        parsed.slides.forEach((slide: any) => {
          if (!slide.options) slide.options = {};
          if (!slide.options.postFX) slide.options.postFX = {};
          slide.options.postFX[key] = value;
        });
        return JSON.stringify(parsed, null, 2);
      } catch (e) {
        return prev;
      }
    });
  }, []);

  const updateSlideProperty = useCallback((path: (string | number)[], value: any) => {
    updateSlideProperties([{ path, value }]);
  }, [updateSlideProperties]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      updateSlideProperty(['image', 'url'], reader.result as string);
    };
    reader.readAsDataURL(file);
  };

  const handleFontUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const allowedExtensions = ['.ttf', '.otf', '.woff2'];
    const extension = file.name.substring(file.name.lastIndexOf('.')).toLowerCase();
    if (!allowedExtensions.includes(extension)) {
      showToast("Formato não suportado. Use .ttf, .otf ou .woff2", "error");
      return;
    }

    setIsUploadingFont(true);
    try {
      const sanitizedName = file.name.replace(/\s+/g, '_').replace(/[^a-zA-Z0-9._-]/g, '');
      const fileName = `${Date.now()}_${sanitizedName}`;

      const { data, error } = await supabase.storage
        .from('fonts')
        .upload(fileName, file);

      if (error) throw error;

      const { data: { publicUrl } } = supabase.storage
        .from('fonts')
        .getPublicUrl(data.path);

      const fontFamily = sanitizedName.split('.')[0].replace(/[^a-zA-Z0-9]/g, '');
      const newFont: CustomFont = {
        id: crypto.randomUUID(),
        name: file.name.split('.')[0],
        family: fontFamily,
        url: publicUrl
      };

      const nextFonts = [...(carousel?.customFonts || []), newFont];
      updateGlobalProperty(['customFonts'], nextFonts);
      showToast("Fonte sincronizada com sucesso!");
    } catch (err: any) {
      console.error("Font upload error:", err);
      showToast("Erro ao subir para o bucket 'fonts'. Verifique as permissões.", "error");
    } finally {
      setIsUploadingFont(false);
      if (fontInputRef.current) fontInputRef.current.value = '';
    }
  };

  const handleRemoveCustomFont = (fontId: string) => {
    const nextFonts = (carousel?.customFonts || []).filter(f => f.id !== fontId);
    updateGlobalProperty(['customFonts'], nextFonts);
    showToast("Fonte removida da biblioteca.");
  };

  const processProjectFile = useCallback((file: File) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        const parsed = JSON.parse(content);
        const result = carouselSchema.safeParse(parsed);
        if (result.success) {
          setDslInput(content);
          setCurrentProjectId(null);
          setSaveFormData({ name: `Importado ${new Date().toLocaleDateString()}`, client: 'Importado' });
          setCurrentIndex(0);
          setView('EDITOR');
          showToast("Projeto importado com sucesso!");
        } else {
          showToast("Arquivo JSON inválido.", "error");
        }
      } catch (err) {
        showToast("Falha ao ler o arquivo.", "error");
      }
    };
    reader.readAsText(file);
  }, [setDslInput, setCurrentProjectId, setSaveFormData, setCurrentIndex, setView, showToast]);

  const handleImportProject = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) processProjectFile(file);
  };

  const handleGlobalDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(true);
  };

  const handleGlobalDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(false);
  };

  const handleGlobalDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(false);
    const file = e.dataTransfer.files?.[0];
    if (file) processProjectFile(file);
  };

  useEffect(() => {
    const handlePaste = (e: ClipboardEvent) => {
      if (view !== 'EDITOR') return;
      const items = e.clipboardData?.items;
      if (!items) return;
      for (let i = 0; i < items.length; i++) {
        if (items[i].type.indexOf('image') !== -1) {
          const blob = items[i].getAsFile();
          if (!blob) continue;
          const reader = new FileReader();
          reader.onload = (event) => {
            const result = event.target?.result as string;
            if (result) {
              if (editingIconBlock) {
                updateSlideProperties([
                  { path: ['blocks', editingIconBlock.index, 'options', 'customIcon'], value: result },
                  { path: ['blocks', editingIconBlock.index, 'options', 'icon'], value: undefined }
                ]);
                showToast("Ícone personalizado colado!");
              } else {
                updateSlideProperty(['image', 'url'], result);
                showToast("Imagem do slide atualizada!");
              }
            }
          };
          reader.readAsDataURL(blob);
          e.preventDefault();
          break;
        }
      }
    };
    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, [view, updateSlideProperty, updateSlideProperties, editingIconBlock, showToast]);

  const loadData = useCallback(async () => {
    setIsSyncing(true);
    try {
      const { data: remoteProjects, error: projError } = await supabase
        .from('projects')
        .select('*')
        .order('updatedAt', { ascending: false });

      if (!projError) {
        setProjects(remoteProjects || []);
      } else {
        console.warn("Remoto falhou (verifique a tabela 'projects'), usando local.");
        const localProjects = JSON.parse(localStorage.getItem(STORAGE_KEYS.PROJECTS_LOCAL) || '[]');
        setProjects(localProjects);
      }

      const { data: palettes, error: palError } = await supabase.from('brand_palettes').select('*');
      if (!palError) {
         setBrandPresets([...DEFAULT_BRAND_PRESETS, ...(palettes || [])]);
      }
    } catch (err: any) {
      console.error("Load failed", err);
      showToast("Falha ao sincronizar com servidor.", "error");
    } finally {
      setIsSyncing(false);
    }
  }, [showToast]);

  useEffect(() => { loadData(); }, [loadData]);

  const currentPalette = brandPresets.find(p => p.id === activePaletteId)?.colors || DEFAULT_BRAND_PRESETS[0].colors;

  const handleRender = useCallback(() => {
    try {
      const parsed = JSON.parse(dslInput);
      const result = carouselSchema.safeParse(parsed);
      if (result.success) {
        setCarousel(result.data);
        setError(null);
      } else {
        setError(result.error.issues.map(e => `[${e.path.join(' → ')}]: ${e.message}`).join('\n'));
      }
    } catch (e: any) {
      setError(`Sintaxe: ${e.message}`);
    }
  }, [dslInput]);

  useEffect(() => { handleRender(); }, [handleRender]);

  const handleNewProject = () => {
    setDslInput(INITIAL_DSL);
    setCurrentProjectId(null);
    setCurrentIndex(0);
    setSaveFormData({ name: '', client: '' });
    setView('EDITOR');
  };

  const handleOpenProject = (proj: Project) => {
    setDslInput(proj.data);
    setCurrentProjectId(proj.id);
    setSaveFormData({ name: proj.name, client: proj.client_name });
    setCurrentIndex(0);
    setView('EDITOR');
  };

  const handleSaveProject = async () => {
    if (!saveFormData.name.trim()) return;
    setIsSyncing(true);
    const now = Date.now();

    const projectObj = {
      id: currentProjectId || crypto.randomUUID(),
      name: saveFormData.name,
      client_name: saveFormData.client || 'Geral',
      data: dslInput,
      slideCount: carousel?.slides.length || 0,
      updatedAt: now
    };

    try {
      const { error } = await supabase.from('projects').upsert(projectObj);
      if (error) throw error;

      setCurrentProjectId(projectObj.id);

      const existing = JSON.parse(localStorage.getItem(STORAGE_KEYS.PROJECTS_LOCAL) || '[]');
      const index = existing.findIndex((p: any) => p.id === projectObj.id);
      let updated;
      if (index >= 0) {
        updated = [...existing];
        updated[index] = projectObj;
      } else {
        updated = [projectObj, ...existing];
      }
      localStorage.setItem(STORAGE_KEYS.PROJECTS_LOCAL, JSON.stringify(updated));

      setShowSaveModal(false);
      showToast("Projeto salvo na Cloud!");
      loadData();
    } catch (err: any) {
      console.error("Save failed", err);
      showToast("Erro ao salvar no servidor. Crie a tabela 'projects'.", "error");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleDeleteProject = async (id: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation(); 
    const confirmed = window.confirm("Excluir projeto permanentemente do servidor?");
    if (!confirmed) return;
    setIsSyncing(true);
    try {
      const { error } = await supabase.from('projects').delete().eq('id', id);
      if (error) throw error;
      showToast("Projeto removido.");
      loadData();
    } catch (err: any) {
      console.error("Delete error:", err);
      showToast("Falha ao excluir no servidor.", "error");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleCanvasMouseUp = (e: React.MouseEvent) => {
    const selection = window.getSelection();
    if (!selection || selection.isCollapsed) return;
    const range = selection.getRangeAt(0);
    const rect = range.getBoundingClientRect();
    const targetBlock = (e.target as HTMLElement).closest('[data-block-index]');
    if (targetBlock) {
       const bIndex = parseInt(targetBlock.getAttribute('data-block-index') || '0', 10);
       const bType = targetBlock.querySelector('[data-block-type]')?.getAttribute('data-block-type') || 'Block';
       const currentBlock = carousel?.slides?.[currentIndex]?.blocks?.[bIndex];
       if (currentBlock) {
          setToolbarState({
            x: Number(rect.left) + Number(rect.width) / 2,
            y: Number(rect.top),
            blockIndex: bIndex,
            blockType: bType,
            options: currentBlock.options || {}
          });
       }
    }
  };

  const startBatchExport = async () => {
    if (!carousel || !canvasRef.current || isExporting || selectedSlidesToExport.size === 0) return;
    setShowExportModal(false);
    const originalIndex = currentIndex;
    const exportIndices = Array.from(selectedSlidesToExport).sort((a, b) => Number(a) - Number(b));
    const images: { name: string; dataUrl: string }[] = [];
    setIsExporting(true);
    try {
      const total = exportIndices.length;
      for (let i = 0; i < total; i++) {
        const slideIdx = exportIndices[i];
        setExportStatus(`Renderizando: ${i + 1}/${total}`);
        setExportProgress(Math.round(((i + 1) / total) * 100));
        setCurrentIndex(slideIdx);
        await new Promise(resolve => setTimeout(resolve, 850));
        const dataUrl = await captureJpeg(canvasRef.current);
        images.push({ name: `slide-${(i + 1).toString().padStart(2, '0')}.jpg`, dataUrl });
      }
      setExportStatus('Comprimindo ZIP...');
      await downloadZip(images, `impact-carousel-${Date.now()}.zip`, dslInput);
      setExportStatus('Sucesso!');
      setTimeout(() => {
        setIsExporting(false);
        setExportProgress(0);
        setCurrentIndex(originalIndex);
      }, 1500);
    } catch (err) {
      setError('Erro crítico na exportação.');
      setIsExporting(false);
      setCurrentIndex(originalIndex);
    }
  };

  const handleApplyPalettePreset = (preset: any) => {
    setActivePaletteId(preset.id);
    const defaults = preset.defaults || {
      bg: preset.colors[0],
      accent: preset.colors[2],
      text: preset.colors[1],
      cardBg: preset.colors[2]
    };
    updateSlideProperties([
      { path: ['options', 'background'], value: defaults.bg },
      { path: ['options', 'accent'], value: defaults.accent },
      { path: ['options', 'text'], value: defaults.text },
      { path: ['options', 'cardBg'], value: defaults.cardBg },
      { path: ['options', 'fontPadrão'], value: preset.font_padrao || 'Inter' },
      { path: ['options', 'fontDestaque'], value: preset.font_destaque || 'Instrument Serif' }
    ]);
  };

  const handleCreatePalette = async () => {
    if (!newPaletteData.name.trim()) return;
    setIsSyncing(true);

    const presetData = {
      name: newPaletteData.name,
      colors: newPaletteData.colors,
      font_padrao: newPaletteData.font_padrao,
      font_destaque: newPaletteData.font_destaque,
      defaults: {
        bg: newPaletteData.colors[0],
        accent: newPaletteData.colors[2],
        text: newPaletteData.colors[1],
        cardBg: newPaletteData.colors[2]
      }
    };

    try {
      if (editingPaletteId) {
        const { error: updateError } = await supabase
          .from('brand_palettes')
          .update(presetData)
          .eq('id', editingPaletteId);
        if (updateError) throw updateError;
        showToast("Branding atualizado!");
      } else {
        const { error: insertError } = await supabase
          .from('brand_palettes')
          .insert([{ ...presetData, id: crypto.randomUUID() }]);
        if (insertError) throw insertError;
        showToast("Marca criada!");
      }
    } catch (err: any) {
      console.error("Supabase error", err);
      showToast("Erro ao sincronizar marca no servidor.", "error");
    } finally {
      setIsCreatingPalette(false);
      setEditingPaletteId(null);
      setNewPaletteData({ 
        name: '', 
        colors: ['#0D0D0D', '#FFFFFF', '#EAB308', '#EAB308', '#EAB308'],
        font_padrao: 'Inter',
        font_destaque: 'Instrument Serif'
      });
      loadData();
      setIsSyncing(false);
    }
  };

  const handleEditPalette = (e: React.MouseEvent, preset: any) => {
    e.stopPropagation();
    setEditingPaletteId(preset.id);
    setNewPaletteData({
      name: preset.name,
      colors: preset.colors,
      font_padrao: preset.font_padrao || 'Inter',
      font_destaque: preset.font_destaque || 'Instrument Serif'
    });
    setIsCreatingPalette(true);
  };

  const allFontOptions = useMemo(() => {
    const custom = (carousel?.customFonts || []).map(f => ({ id: f.family, label: `${f.name} (Custom)` }));
    return [...GOOGLE_FONTS, ...custom];
  }, [carousel?.customFonts]);

  const clients = useMemo(() => Array.from(new Set(projects.map(p => p.client_name))).sort(), [projects]);
  const filteredProjects = useMemo(() => projects.filter(p => {
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase()) || p.client_name.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesClient = selectedClientFilter ? p.client_name === selectedClientFilter : true;
    return matchesSearch && matchesClient;
  }), [projects, searchQuery, selectedClientFilter]);

  return (
    <div onDragOver={handleGlobalDragOver} onDragLeave={handleGlobalDragLeave} onDrop={handleGlobalDrop} className="flex h-screen w-full bg-[#050507] text-zinc-300 font-sans overflow-hidden relative">
      {isDraggingFile && (
        <div className="fixed inset-0 z-[10000] bg-brand/10 backdrop-blur-sm border-4 border-dashed border-brand/50 flex items-center justify-center pointer-events-none">
          <div className="bg-zinc-900 p-10 rounded-[40px] shadow-2xl flex flex-col items-center gap-6 animate-in zoom-in-95">
             <Upload size={64} className="text-brand animate-bounce" />
             <p className="text-xl font-black text-white uppercase italic tracking-tighter">Solte o arquivo para importar</p>
          </div>
        </div>
      )}

      {toast && (
        <div className={`fixed bottom-12 left-1/2 -translate-x-1/2 z-[9999] px-12 py-6 rounded-[32px] flex items-center gap-6 animate-in slide-in-from-bottom-12 fade-in duration-500 shadow-[0_30px_90px_rgba(0,0,0,0.6)] backdrop-blur-3xl border border-white/10 ${toast.type === 'success' ? 'bg-brand/95 text-black' : 'bg-red-500/95 text-white'}`}>
          {toast.type === 'success' ? <CheckCircle size={28} strokeWidth={3} /> : <AlertCircle size={28} strokeWidth={3} />}
          <span className="text-[16px] font-black uppercase tracking-[0.1em]">{toast.message}</span>
        </div>
      )}

      <input type="file" ref={importInputRef} onChange={handleImportProject} accept=".json" className="hidden" />
      <input type="file" ref={fontInputRef} onChange={handleFontUpload} accept=".ttf,.otf,.woff2" className="hidden" />

      {toolbarState && (
        <FloatingTextToolbar state={toolbarState} onClose={() => setToolbarState(null)} onUpdate={updateSlideProperties} />
      )}

      {showExportModal && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in" onClick={() => setShowExportModal(false)}>
           <div className="w-full max-w-2xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <div className="space-y-1">
                   <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Exportar Carrossel</h2>
                   <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.2em]">ZIP conterá imagens + JSON do projeto</p>
                 </div>
                 <button onClick={() => setShowExportModal(false)} className="p-3 hover:bg-white/5 rounded-full text-zinc-500 transition-colors"><X size={24}/></button>
              </div>
              <div className="grid grid-cols-4 gap-4 max-h-[400px] overflow-y-auto custom-scrollbar p-1">
                 {carousel?.slides.map((s, idx) => (
                    <button key={idx} onClick={() => { const next = new Set(selectedSlidesToExport); if (next.has(idx)) next.delete(idx); else next.add(idx); setSelectedSlidesToExport(next); }} className={`relative aspect-[4/5] rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-3 overflow-hidden ${selectedSlidesToExport.has(idx) ? 'border-brand bg-brand/10' : 'border-white/5 bg-black/40 hover:border-white/20'}`}>
                       <div className={`w-10 h-10 rounded-full flex items-center justify-center ${selectedSlidesToExport.has(idx) ? 'bg-brand text-black' : 'bg-zinc-800 text-zinc-500'}`}><span className="font-black text-xs">{idx + 1}</span></div>
                       <p className="text-[10px] font-black uppercase text-zinc-500 tracking-widest truncate px-2 w-full">{s.template.replace(/_/g, ' ')}</p>
                       {selectedSlidesToExport.has(idx) && (<div className="absolute top-2 right-2 text-brand"><CheckCircle2 size={16} /></div>)}
                    </button>
                 ))}
              </div>
              <div className="flex gap-4 pt-4 border-t border-white/5">
                 <button onClick={() => setSelectedSlidesToExport(new Set())} className="px-6 py-5 text-[10px] font-black text-zinc-500 uppercase tracking-widest hover:text-white transition-all">Limpar</button>
                 <button onClick={() => setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i)))} className="px-6 py-5 text-[10px] font-black text-brand uppercase tracking-widest hover:text-brand/80 transition-all">Todos</button>
                 <button onClick={startBatchExport} disabled={selectedSlidesToExport.size === 0} className="flex-1 py-5 bg-brand hover:bg-brand/80 disabled:opacity-30 text-black font-black uppercase rounded-2xl shadow-xl transition-all flex items-center justify-center gap-3"><Download size={18} strokeWidth={3} /> Gerar {selectedSlidesToExport.size} Slides</button>
              </div>
           </div>
        </div>
      )}

      {editingIconBlock && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in" onClick={() => setEditingIconBlock(null)}>
           <div className="w-full max-w-2xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <div className="space-y-1">
                   <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Escolher Ícone</h2>
                   <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.2em]">Biblioteca ou CTRL+V para PNG</p>
                 </div>
                 <button onClick={() => setEditingIconBlock(null)} className="p-3 hover:bg-white/5 rounded-full text-zinc-500"><X size={24}/></button>
              </div>
              <div className="grid grid-cols-4 sm:grid-cols-6 gap-4 p-1">
                 {ICON_LIBRARY_PRESETS.map(item => (
                    <button key={item.id} onClick={() => { updateSlideProperties([{ path: ['blocks', editingIconBlock.index, 'options', 'icon'], value: item.id }, { path: ['blocks', editingIconBlock.index, 'options', 'customIcon'], value: undefined }]); setEditingIconBlock(null); }} className={`flex flex-col items-center justify-center gap-3 p-5 rounded-3xl border-2 transition-all group ${editingIconBlock.block.options?.icon === item.id ? 'border-brand bg-brand/10 text-brand' : 'border-white/5 bg-black/40 hover:border-brand/50'}`}><item.icon size={32} strokeWidth={1.5} className="transition-transform group-hover:scale-110" /><span className="text-[8px] font-black uppercase tracking-tighter text-zinc-600 group-hover:text-brand">{item.label}</span></button>
                 ))}
              </div>
              <div className="space-y-3">
                 <label className="text-[9px] font-black uppercase text-zinc-500 px-1 tracking-widest">Personalizado (URL ou SVG)</label>
                 <div className="flex gap-3"><input type="text" placeholder="https://... ou <svg..." className="flex-1 bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm font-bold text-white outline-none focus:border-brand/50 transition-all" value={iconInput} onChange={(e) => setIconInput(e.target.value)} /><button onClick={() => { updateSlideProperties([{ path: ['blocks', editingIconBlock.index, 'options', 'customIcon'], value: iconInput }, { path: ['blocks', editingIconBlock.index, 'options', 'icon'], value: undefined }]); setEditingIconBlock(null); }} className="px-8 py-4 bg-zinc-800 text-white font-black uppercase text-[10px] rounded-2xl hover:bg-zinc-700 transition-all">Aplicar</button></div>
              </div>
           </div>
        </div>
      )}

      {isCreatingPalette && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in" onClick={() => { setIsCreatingPalette(false); setEditingPaletteId(null); }}>
           <div className="w-full max-w-xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <div className="space-y-1">
                   <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">{editingPaletteId ? 'Editar Branding' : 'Novo Branding'}</h2>
                   <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.2em]">Cores e Fontes mestras da marca</p>
                 </div>
                 <button onClick={() => { setIsCreatingPalette(false); setEditingPaletteId(null); }} className="p-3 hover:bg-white/5 rounded-full text-zinc-500"><X size={24}/></button>
              </div>
              <div className="space-y-6">
                <input type="text" value={newPaletteData.name} onChange={(e) => setNewPaletteData({ ...newPaletteData, name: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-6 text-base text-white font-bold outline-none focus:border-brand/50 transition-all" placeholder="Nome da Marca" />
                <div className="grid grid-cols-2 gap-4">
                  <select value={newPaletteData.font_padrao} onChange={(e) => setNewPaletteData({ ...newPaletteData, font_padrao: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-xl py-3 px-3 text-[11px] font-bold text-white outline-none">
                    {allFontOptions.map(f => <option key={f.id} value={f.id}>{f.label}</option>)}
                  </select>
                  <select value={newPaletteData.font_destaque} onChange={(e) => setNewPaletteData({ ...newPaletteData, font_destaque: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-xl py-3 px-3 text-[11px] font-bold text-white outline-none">
                    {allFontOptions.map(f => <option key={f.id} value={f.id}>{f.label}</option>)}
                  </select>
                </div>
                <div className="grid grid-cols-5 gap-4">
                   {['Fundo', 'Texto', 'Accent', 'HL', 'Cards'].map((l, i) => (
                     <div key={i} className="flex flex-col items-center gap-2">
                       <div className="relative w-10 h-10 rounded-full overflow-hidden border border-white/10">
                         <input type="color" value={newPaletteData.colors[i]} onChange={(e) => { const c = [...newPaletteData.colors]; c[i] = e.target.value; setNewPaletteData({ ...newPaletteData, colors: c }); }} className="absolute inset-[-10px] w-[150%] h-[150%] cursor-pointer p-0 m-0 border-none" />
                       </div>
                       <span className="text-[7px] font-black uppercase text-zinc-600">{l}</span>
                     </div>
                   ))}
                </div>
              </div>
              <button onClick={handleCreatePalette} className="w-full py-4 bg-brand text-black font-black uppercase rounded-2xl shadow-2xl transition-all">Sincronizar Branding</button>
           </div>
        </div>
      )}

      {isExporting && (
        <div className="fixed inset-0 z-[500] flex items-center justify-center bg-black/80 backdrop-blur-3xl animate-in fade-in">
           <div className="w-full max-md space-y-10 text-center px-10">
              <div className="relative inline-block"><div className="absolute inset-0 blur-3xl bg-brand/20 animate-pulse rounded-full" /><Loader2 size={64} className="animate-spin text-brand relative mx-auto" strokeWidth={3} /></div>
              <div className="space-y-4"><h2 className="text-2xl font-black text-white uppercase italic tracking-tighter animate-pulse">{exportStatus}</h2><div className="h-2 w-full bg-white/5 rounded-full overflow-hidden"><div className="h-full bg-brand transition-all duration-500" style={{ width: `${exportProgress}%` }} /></div><p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">{exportProgress}% COMPLETO</p></div>
           </div>
        </div>
      )}

      {showSaveModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center p-6 bg-black/90 backdrop-blur-2xl animate-in fade-in" onClick={() => setShowSaveModal(false)}>
           <div className="w-full max-w-md bg-zinc-900 border border-white/10 rounded-[32px] p-8 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <h2 className="text-lg font-black text-white uppercase tracking-tight">Salvar na Cloud</h2>
              <div className="space-y-6">
                <input type="text" value={saveFormData.name} onChange={(e) => setSaveFormData({ ...saveFormData, name: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm text-white font-bold outline-none" placeholder="Nome do Projeto" />
                <input type="text" list="clients" value={saveFormData.client} onChange={(e) => setSaveFormData({ ...saveFormData, client: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm text-white font-bold outline-none" placeholder="Cliente" /><datalist id="clients">{clients.map(c => <option key={c} value={c} />)}</datalist>
              </div>
              <button onClick={handleSaveProject} className="w-full py-5 bg-brand text-black font-black uppercase rounded-2xl shadow-xl flex items-center justify-center gap-3 disabled:opacity-30 transition-all">{isSyncing ? <Loader2 className="animate-spin" size={18} /> : <Save size={18} />}Sincronizar Cloud</button>
           </div>
        </div>
      )}

      {view === 'DASHBOARD' ? (
        <div className="min-h-screen w-full bg-[#050507] text-white flex flex-col overflow-y-auto custom-scrollbar">
          <header className="px-10 py-8 flex items-center justify-between border-b border-white/5 sticky top-0 bg-[#050507]/80 backdrop-blur-xl z-50">
            <div className="flex items-center gap-4"><img src={LOGO_URL} className="h-10 object-contain" alt="Logo" /><div className="flex items-center gap-2 px-3 py-1 bg-zinc-800 rounded-lg text-[9px] font-black uppercase text-zinc-500"><Database size={10} className="text-brand" /> Cloud Active</div></div>
            <div className="flex-1 max-w-xl mx-20 relative"><Search className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-600" size={18} /><input type="text" placeholder="Pesquisar projetos na nuvem..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-2xl py-3 pl-12 pr-4 text-[13px] font-bold text-white outline-none focus:border-brand/50 transition-all" /></div>
            <div className="flex gap-4"><button onClick={() => importInputRef.current?.click()} className="flex items-center gap-2 px-6 py-3 bg-white/5 border border-white/10 text-white font-black uppercase text-[11px] rounded-xl"><Upload size={16} /> JSON Import</button><button onClick={handleNewProject} className="flex items-center gap-2 px-6 py-3 bg-brand text-black font-black uppercase text-[11px] rounded-xl shadow-xl shadow-brand/10"><Plus size={16} strokeWidth={3} /> Criar Novo</button></div>
          </header>
          <main className="p-10 max-w-[1400px] mx-auto w-full">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredProjects.map(proj => (
                  <div key={proj.id} onClick={() => handleOpenProject(proj)} className="h-80 bg-zinc-900/40 border border-white/5 rounded-[32px] p-8 flex flex-col justify-between transition-all cursor-pointer group hover:border-brand/30">
                      <div className="flex items-start justify-between"><div className="w-12 h-12 bg-black/40 rounded-2xl flex items-center justify-center border border-white/5 group-hover:border-brand/20"><Library size={20} className="text-zinc-600 group-hover:text-brand" /></div><button onClick={(e) => handleDeleteProject(proj.id, e)} className="p-2 text-zinc-700 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={16} /></button></div>
                      <div className="space-y-3"><div className="flex items-center gap-1.5 text-brand font-black uppercase tracking-widest text-[9px]"><UserCircle size={10} />{proj.client_name}</div><h3 className="text-base font-black text-white truncate">{proj.name}</h3><div className="flex gap-4 opacity-40 text-[9px] font-black uppercase"><span className="flex items-center gap-1"><Layers size={10} /> {proj.slideCount} slides</span><span className="flex items-center gap-1"><Clock size={10} /> {new Date(proj.updatedAt).toLocaleDateString()}</span></div></div>
                  </div>
                ))}
            </div>
          </main>
        </div>
      ) : (
        <div className="flex h-screen w-full">
          <aside className="w-[440px] border-r border-white/5 flex flex-col bg-zinc-900/50 backdrop-blur-2xl z-20 shrink-0">
            <header className="p-5 border-b border-white/5 flex flex-col gap-4">
              <div className="flex items-center justify-between"><button onClick={() => setView('DASHBOARD')} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg text-zinc-500"><Home size={18} /></button><img src={LOGO_URL} className="h-8 object-contain" /><button onClick={() => setShowSaveModal(true)} className="p-2 bg-brand/10 hover:bg-brand/20 text-brand rounded-lg transition-all">{isSyncing ? <Loader2 size={18} className="animate-spin" /> : <Save size={18} />}</button></div>
              <nav className="flex gap-1 p-1 bg-black/40 rounded-xl">
                {[
                  { id: 'TEMPLATES', icon: Library },
                  { id: 'BLOCKS', icon: TypeIcon },
                  { id: 'DESIGN', icon: Palette },
                  { id: 'FX', icon: Sparkles },
                  { id: 'ASSETS', icon: ImageIcon },
                  { id: 'JSON', icon: FileJson },
                ].map(tab => (<button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex-1 py-3 rounded-lg flex items-center justify-center transition-all ${activeTab === tab.id ? 'bg-zinc-800 text-brand' : 'text-zinc-500 hover:text-white'}`}><tab.icon size={16} /></button>))}
              </nav>
            </header>
            <div className="flex-1 overflow-y-auto custom-scrollbar p-5 space-y-8">
              {activeTab === 'DESIGN' ? (
                <div className="space-y-10 animate-in slide-in-from-left-4 duration-300">
                  <section className="space-y-4">
                    <div className="flex items-center justify-between"><div className="flex items-center gap-2"><Palette size={16} className="text-brand" /><h3 className="text-[10px] font-black text-white uppercase tracking-widest">Marcas Sincronizadas</h3></div><button onClick={() => setIsCreatingPalette(true)} className="p-1.5 bg-brand/10 text-brand rounded-lg hover:bg-brand/20 transition-all"><Plus size={14} strokeWidth={3} /></button></div>
                    <div className="grid grid-cols-1 gap-2">
                       {brandPresets.map(p => (
                         <button key={p.id} onClick={() => handleApplyPalettePreset(p)} className={`w-full p-4 border rounded-2xl flex items-center justify-between group transition-all ${activePaletteId === p.id ? 'bg-brand/10 border-brand' : 'bg-white/5 border-white/5 hover:border-white/10'}`}>
                           <div className="flex items-center gap-3"><div className="flex -space-x-1">{p.colors.slice(0, 3).map((c: any, i: any) => (<div key={i} className="w-4 h-4 rounded-full border border-zinc-900" style={{ backgroundColor: c }} />))}</div><span className="text-[11px] font-black uppercase text-zinc-400">{p.name}</span></div>
                           <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                             {!DEFAULT_BRAND_PRESETS.find(d => d.id === p.id) && <button onClick={(e) => handleEditPalette(e, p)} className="p-1.5 text-zinc-500 hover:text-brand"><Pencil size={12}/></button>}
                           </div>
                         </button>
                       ))}
                    </div>
                  </section>

                  <section className="space-y-4 pt-6 border-t border-white/5">
                    <div className="flex items-center gap-2"><CloudUpload size={16} className="text-brand" /><h3 className="text-[10px] font-black text-white uppercase tracking-widest">Biblioteca de Fontes</h3></div>
                    <div className="grid grid-cols-1 gap-2">
                       {carousel?.customFonts?.map(font => (
                         <div key={font.id} className="flex items-center justify-between p-4 bg-white/5 border border-white/5 rounded-xl group">
                            <div className="flex flex-col min-w-0"><span className="text-[10px] font-black text-white uppercase truncate">{font.name}</span><span className="text-[7px] text-zinc-600 font-mono truncate uppercase">{font.family} (Cloud)</span></div>
                            <button onClick={() => handleRemoveCustomFont(font.id)} className="p-2 text-zinc-700 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={14} /></button>
                         </div>
                       ))}
                       <button onClick={() => fontInputRef.current?.click()} disabled={isUploadingFont} className="w-full py-6 border-2 border-dashed border-white/5 rounded-2xl flex flex-col items-center justify-center gap-2 hover:border-brand/30 hover:bg-brand/5 text-zinc-600 hover:text-brand transition-all">
                          {isUploadingFont ? <Loader2 size={24} className="animate-spin" /> : <HardDrive size={24} />}
                          <span className="text-[9px] font-black uppercase tracking-widest">Sincronizar .ttf / .otf / .woff2</span>
                       </button>
                    </div>
                  </section>

                  <section className="space-y-6 pt-6 border-t border-white/5">
                    <div className="flex items-center gap-2"><Baseline size={16} className="text-brand" /><h3 className="text-[10px] font-black text-white uppercase tracking-widest">Tipografia Atual</h3></div>
                    <div className="space-y-4">
                      <div className="space-y-2"><label className="text-[9px] font-black uppercase text-zinc-500">Fonte Padrão</label><select value={currentSlide?.options?.fontPadrão || 'Inter'} onChange={(e) => updateSlideProperty(['options', 'fontPadrão'], e.target.value)} className="w-full bg-black/40 border border-white/5 rounded-xl py-3 px-3 text-[11px] font-bold text-white outline-none">{allFontOptions.map(f => <option key={f.id} value={f.id}>{f.label}</option>)}</select></div>
                      <div className="space-y-2"><label className="text-[9px] font-black uppercase text-zinc-500">Fonte Destaque</label><select value={currentSlide?.options?.fontDestaque || 'Instrument Serif'} onChange={(e) => updateSlideProperty(['options', 'fontDestaque'], e.target.value)} className="w-full bg-black/40 border border-white/5 rounded-xl py-3 px-3 text-[11px] font-bold text-white outline-none">{allFontOptions.map(f => <option key={f.id} value={f.id}>{f.label}</option>)}</select></div>
                    </div>
                  </section>

                  <section className="space-y-8 pt-6 border-t border-white/5">
                    <TransformControl label="Margens (Padding)" value={currentSlide?.options?.padding ?? 80} min={20} max={200} step={4} onChange={(v) => updateSlideProperty(['options', 'padding'], v)} />
                    <TransformControl label="Entre Blocos (Gap)" value={currentSlide?.options?.blockGap ?? 16} min={0} max={160} step={2} onChange={(v) => updateSlideProperty(['options', 'blockGap'], v)} />
                  </section>
                </div>
              ) : activeTab === 'BLOCKS' ? (
                <div className="space-y-4 animate-in fade-in slide-in-from-left-4 duration-300">
                    {carousel?.slides[currentIndex]?.blocks.map((block, bIdx) => (
                      <div key={bIdx} className="bg-white/5 border border-white/5 rounded-[24px] overflow-hidden group">
                        <div className="px-5 py-3 bg-black/20 flex items-center justify-between border-b border-white/5"><span className="text-[9px] font-black uppercase text-zinc-500">{block.type}</span><button onClick={() => { const next = [...carousel.slides[currentIndex].blocks]; next.splice(bIdx, 1); updateSlideProperty(['blocks'], next); }} className="p-1 text-zinc-700 hover:text-red-400"><Trash2 size={12} /></button></div>
                        <div className="p-5 space-y-4">
                           {block.type === 'USER' ? (
                             <div className="space-y-3"><input type="text" value={block.content as string} onChange={(e) => updateSlideProperty(['blocks', bIdx, 'content'], e.target.value)} className="w-full bg-black/40 border border-white/5 rounded-xl p-3 text-[12px] font-bold text-white outline-none" placeholder="Nome" /><input type="text" value={block.options?.handle || ''} onChange={(e) => updateSlideProperty(['blocks', bIdx, 'options', 'handle'], e.target.value)} className="w-full bg-black/40 border border-white/5 rounded-xl p-3 text-[11px] font-bold text-brand outline-none" placeholder="@handle" /></div>
                           ) : block.type !== 'SPACER' ? (
                             <textarea value={block.content as any} onChange={(e) => updateSlideProperty(['blocks', bIdx, 'content'], block.type === 'LIST' ? e.target.value.split('\n') : e.target.value)} className="w-full bg-black/40 border border-white/5 rounded-xl p-4 text-[12px] font-bold text-white outline-none focus:border-brand/50 min-h-[100px]" placeholder="Conteúdo do bloco..." />
                           ) : null}
                           <div className="grid grid-cols-2 gap-3">
                              <div className="space-y-1"><span className="text-[8px] font-black uppercase text-zinc-600">Fonte</span><select value={block.options?.fontVariant || 'padrão'} onChange={(e) => updateSlideProperty(['blocks', bIdx, 'options', 'fontVariant'], e.target.value)} className="w-full bg-black/40 border border-white/5 rounded-lg py-2 px-2 text-[9px] font-bold text-white"><option value="padrão">Padrão</option><option value="destaque">Destaque</option></select></div>
                              <TransformControl label="Size" value={block.options?.fontSize || 32} min={10} max={400} step={1} onChange={(v) => updateSlideProperty(['blocks', bIdx, 'options', 'fontSize'], v)} />
                           </div>
                        </div>
                      </div>
                    ))}
                    <button onClick={() => { const n = [...carousel!.slides[currentIndex].blocks, { type: 'PARAGRAPH', content: 'Novo parágrafo...', options: { fontSize: 32 } }]; updateSlideProperty(['blocks'], n); }} className="w-full py-6 border-2 border-dashed border-white/5 rounded-[32px] flex flex-col items-center justify-center gap-2 text-zinc-600 hover:text-brand hover:border-brand/30 transition-all"><Plus size={20}/><span className="text-[9px] font-black uppercase tracking-widest">Novo Bloco</span></button>
                </div>
              ) : activeTab === 'ASSETS' ? (
                <div className="space-y-6">
                   <div className="relative aspect-video rounded-3xl overflow-hidden bg-zinc-950 border border-white/5 group">
                      {imageConfig?.url ? (<img src={imageConfig.url} className="w-full h-full object-contain" />) : (<div className="w-full h-full flex flex-col items-center justify-center gap-2 text-zinc-700"><ImageIcon size={40}/><span className="text-[9px] font-black uppercase">Sem Imagem</span></div>)}
                      <input type="file" onChange={handleImageUpload} className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" />
                   </div>
                   {imageConfig && (
                     <div className="space-y-6">
                        <div className="grid grid-cols-5 gap-2">{IMAGE_TYPE_PRESETS.map(p => (<button key={p.id} onClick={() => updateSlideProperty(['image', 'type'], p.id)} className={`p-2.5 rounded-xl border flex items-center justify-center transition-all ${imageConfig.type === p.id ? 'bg-brand text-black border-brand' : 'bg-black/40 border-white/5 text-zinc-500'}`}><p.icon size={16}/></button>))}</div>
                        <div className="grid grid-cols-2 gap-4"><TransformControl label="Box X" value={imageConfig.boxX || 0} min={-500} max={500} step={1} onChange={(v) => updateSlideProperty(['image', 'boxX'], v)} /><TransformControl label="Box Y" value={imageConfig.boxY || 0} min={-500} max={500} step={1} onChange={(v) => updateSlideProperty(['image', 'boxY'], v)} /></div>
                        <div className="grid grid-cols-2 gap-4"><TransformControl label="Zoom" value={imageConfig.boxScale || 1} min={0.5} max={3} step={0.05} onChange={(v) => updateSlideProperty(['image', 'boxScale'], v)} /><TransformControl label="Rotate" value={imageConfig.boxRotation || 0} min={-180} max={180} step={1} onChange={(v) => updateSlideProperty(['image', 'boxRotation'], v)} /></div>
                     </div>
                   )}
                </div>
              ) : activeTab === 'TEMPLATES' ? (
                <div className="grid grid-cols-1 gap-2">
                   {templates.map(tpl => (<button key={tpl.name} onClick={() => updateSlideProperty(['template'], tpl.name)} className={`w-full p-4 border rounded-2xl flex items-center gap-4 transition-all ${currentSlide?.template === tpl.name ? 'bg-brand/10 border-brand' : 'bg-white/5 border-white/5 hover:border-white/10'}`}><div className={`w-10 h-10 rounded-xl flex items-center justify-center ${currentSlide?.template === tpl.name ? 'bg-brand text-black' : 'bg-black text-zinc-600'}`}><Library size={18}/></div><div className="text-left"><p className={`text-[10px] font-black uppercase ${currentSlide?.template === tpl.name ? 'text-brand' : 'text-white'}`}>{tpl.name.replace(/_/g, ' ')}</p><p className="text-[8px] text-zinc-600 font-medium truncate max-w-[200px]">{tpl.description}</p></div></button>))}
                </div>
              ) : activeTab === 'JSON' ? (
                <textarea value={dslInput} onChange={(e) => setDslInput(e.target.value)} className="w-full h-[600px] bg-black/40 p-4 font-mono text-[10px] border border-white/5 rounded-2xl outline-none custom-scrollbar" spellCheck={false} />
              ) : null}
            </div>
            <footer className="p-5 border-t border-white/5 bg-zinc-950">
               <button onClick={() => { setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i))); setShowExportModal(true); }} className="w-full py-4 bg-brand text-black font-black rounded-xl text-[10px] uppercase shadow-lg flex items-center justify-center gap-3 active:scale-95"><Download size={16} strokeWidth={3} /> Exportar Tudo</button>
            </footer>
          </aside>
          <main className="flex-1 bg-[#121214] relative flex flex-col">
            {error && <div className="absolute top-5 left-1/2 -translate-x-1/2 z-[100] bg-red-500 text-white px-6 py-3 rounded-2xl flex items-center gap-3 shadow-2xl animate-in slide-in-from-top-4"><AlertCircle size={18}/><span className="text-[11px] font-black uppercase">{error}</span></div>}
            <div className="absolute top-5 right-5 z-40 flex items-center gap-1 bg-black/30 backdrop-blur-xl p-1.5 rounded-xl border border-white/5"><button onClick={() => setZoom(Math.max(0.1, zoom - 0.05))} className="p-1.5 text-zinc-500 hover:text-white"><ZoomOut size={16} /></button><div className="px-2 text-[10px] font-black font-mono text-zinc-400">{(zoom * 100).toFixed(0)}%</div><button onClick={() => setZoom(Math.min(1.5, zoom + 0.05))} className="p-1.5 text-zinc-500 hover:text-white"><ZoomIn size={16} /></button></div>
            <div className="flex-1 flex items-center justify-center overflow-auto p-20" onMouseUp={handleCanvasMouseUp}><div style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }} className="transition-transform duration-500 shadow-[0_60px_150px_rgba(0,0,0,0.8)] shrink-0">{carousel?.slides?.[currentIndex] && <SlideCanvas slide={carousel.slides[currentIndex]} index={currentIndex} canvasRef={canvasRef} onEditIcon={(b, i) => setEditingIconBlock({ block: b, index: i })} customFonts={carousel.customFonts} />}</div></div>
            {carousel && carousel.slides.length > 0 && (<div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-40 flex items-center gap-6 bg-black/50 backdrop-blur-2xl px-8 py-4 rounded-full border border-white/5 shadow-2xl transition-all hover:border-white/10"><button disabled={currentIndex === 0} onClick={() => setCurrentIndex(prev => prev - 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronLeft size={20}/></button><div className="flex gap-2.5">{carousel.slides.map((_, i) => (<button key={i} onClick={() => setCurrentIndex(i)} className={`h-2 transition-all duration-300 rounded-full ${currentIndex === i ? 'w-8 bg-brand' : 'w-2 bg-white/10 hover:bg-white/20'}`} />))}</div><button disabled={currentIndex === carousel.slides.length - 1} onClick={() => setCurrentIndex(prev => prev + 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronRight size={20}/></button></div>)}
          </main>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useMemo } from 'react'
import { ValidatedSlide } from '../template-dsl/schema'
import { TOKENS } from '../design-tokens/tokens'
import { renderBlock } from './renderBlock'
import { templateRegistry } from '../domain/templates/TemplateRegistry'
import { Image as ImageIcon, Box, User, Layers, Package } from 'lucide-react'
import { Block, CustomFont } from '../types'

export const SlideCanvas: React.FC<{ 
  slide: ValidatedSlide, 
  index: number, 
  canvasRef: React.RefObject<HTMLDivElement>,
  onEditIcon?: (block: Block, index: number) => void,
  customFonts?: CustomFont[]
}> = ({ slide, index, canvasRef, onEditIcon, customFonts }) => {
  const isLight = slide.options?.theme === 'light'
  const templateDef = templateRegistry.get(slide.template)

  const theme = useMemo(() => {
    const baseBackground = isLight ? '#F2F2F2' : '#0D0D0D'
    const baseTextPrimary = isLight ? '#000000' : '#FFFFFF'
    const baseTextSecondary = isLight ? '#333333' : 'rgba(255, 255, 255, 0.9)'

    return {
      ...TOKENS,
      typography: {
        ...TOKENS.typography,
        fontFamily: slide.options?.fontPadrão || TOKENS.typography.fontFamily,
        fontFamilySecondary: slide.options?.fontDestaque || '"Instrument Serif", serif',
      },
      colors: {
        ...TOKENS.colors,
        background: slide.options?.background || baseBackground,
        textPrimary: slide.options?.text || baseTextPrimary,
        textSecondary: slide.options?.text ? `${slide.options.text}cc` : baseTextSecondary,
        accent: slide.options?.accent || TOKENS.colors.accent,
        highlight: slide.options?.accent || TOKENS.colors.highlight,
        cardBg: slide.options?.cardBg || slide.options?.accent || TOKENS.colors.accent,
        cardTextColor: slide.options?.cardTextColor,
        cardOpacity: slide.options?.cardOpacity !== undefined ? slide.options.cardOpacity : 1,
        hlBgColor: slide.options?.hlBgColor || slide.options?.accent || TOKENS.colors.accent,
        hlTextColor: slide.options?.hlTextColor || '#000000',
      }
    }
  }, [isLight, slide.options?.background, slide.options?.accent, slide.options?.text, slide.options?.cardBg, slide.options?.cardTextColor, slide.options?.cardOpacity, slide.options?.hlBgColor, slide.options?.hlTextColor, slide.options?.fontPadrão, slide.options?.fontDestaque])

  if (!templateDef) return <div ref={canvasRef} className="w-[1080px] h-[1350px] bg-red-900 flex items-center justify-center text-white font-bold">ERROR: TEMPLATE NOT FOUND</div>

  const imageConfig = slide.image;
  const texture = slide.options?.texture;
  const fx = slide.options?.postFX;

  const blockGap = slide.options?.blockGap !== undefined ? slide.options.blockGap : 16;
  const sectionGap = slide.options?.sectionGap !== undefined ? slide.options.sectionGap : 48;
  const padding = slide.options?.padding !== undefined ? slide.options.padding : 80;

  const renderTornPaperSVG = () => {
    if (!imageConfig?.hasTornEdges) return null;
    const maskId = `tornMask-${index}`;
    return (
      <svg width="0" height="0" className="absolute">
        <defs>
          <clipPath id={maskId} clipPathUnits="objectBoundingBox">
            <path d="M0.04,0.06 C0.1,0.04 0.15,0.08 0.2,0.05 C0.25,0.03 0.3,0.07 0.35,0.04 C0.4,0.02 0.45,0.06 0.5,0.04 C0.55,0.03 0.6,0.07 0.65,0.05 C0.7,0.03 0.75,0.06 0.8,0.04 C0.85,0.03 0.9,0.07 0.96,0.05 C0.98,0.1 0.95,0.15 0.97,0.2 C0.99,0.25 0.96,0.3 0.98,0.35 C1.0,0.4 0.97,0.45 0.99,0.5 C1.0,0.55 0.96,0.6 0.98,0.65 C1.0,0.7 0.97,0.75 0.99,0.8 C1.0,0.85 0.96,0.9 0.94,0.96 C0.9,0.98 0.85,0.95 0.8,0.97 C0.75,0.99 0.7,0.96 0.65,0.98 C0.6,1.0 0.55,0.97 0.5,0.99 C0.45,1.0 0.4,0.96 0.35,0.98 C0.3,1.0 0.25,0.97 0.2,0.99 C0.15,1.0 0.1,0.96 0.04,0.94 C0.02,0.9 0.05,0.85 0.03,0.8 C0.01,0.75 0.04,0.7 0.02,0.65 C0.0,0.6 0.03,0.55 0.01,0.5 C0.0,0.45 0.04,0.4 0.02,0.35 C0.0,0.3 0.03,0.25 0.01,0.2 C0.0,0.15 0.04,0.1 0.04,0.06 Z" />
          </clipPath>
        </defs>
      </svg>
    );
  };

  const renderImage = (className: string, fit: 'cover' | 'contain' = 'cover', extraStyle: React.CSSProperties = {}) => {
    if (!imageConfig?.url) return null;
    const imgScale = imageConfig.imageScale ?? 1;
    const imgRotation = imageConfig.imageRotation ?? 0;
    const imgX = imageConfig.imageX ?? 0;
    const imgY = imageConfig.imageY ?? 0;
    const opacity = imageConfig.backgroundOpacity ?? 1;
    const maskId = `tornMask-${index}`;
    return (
      <div className={`${className} transition-all duration-300 ease-out`} style={{ clipPath: imageConfig.hasTornEdges ? `url(#${maskId})` : 'none', ...extraStyle }}>
        <img src={imageConfig.url} className={`w-full h-full ${fit === 'cover' ? 'object-cover' : 'object-contain'}`} style={{ objectPosition: `calc(50% + ${imgX}px) calc(50% + ${imgY}px)`, transform: `scale(${imgScale}) rotate(${imgRotation}deg)`, transformOrigin: 'center', opacity: opacity }} alt="" />
      </div>
    );
  };

  const renderBlocks = () => (
    <div className="w-full relative z-30 flex flex-col" style={{ gap: `${blockGap}px` }}>
      {slide.blocks.map((b, i) => <React.Fragment key={i}>{renderBlock(b, theme, onEditIcon, false, 0, i)}</React.Fragment>)}
    </div>
  );

  const renderFXOverlays = () => {
    const overlays: React.ReactNode[] = [];
    const fxId = `fx-${index}`;
    if (fx?.lightingIntensity && fx.lightingIntensity > 0) overlays.push(<div key="fx-lighting" className="absolute inset-0 pointer-events-none z-[42]" style={{ background: `radial-gradient(circle at 30% 20%, rgba(255,255,255,${fx.lightingIntensity * 0.15}), transparent 80%)`, mixBlendMode: 'screen' }} />);
    if (fx?.vignette && fx.vignette > 0) overlays.push(<div key="fx-vignette" className="absolute inset-0 pointer-events-none z-[48]" style={{ background: `radial-gradient(circle, transparent 40%, rgba(0,0,0,${fx.vignette * 0.6}) 100%)`, mixBlendMode: 'multiply' }} />);
    if (fx?.noiseAmount && fx.noiseAmount > 0) overlays.push(<div key="fx-noise" className="absolute inset-0 pointer-events-none z-[49]" style={{ opacity: fx.noiseAmount, mixBlendMode: (fx.noiseMode as any) || 'multiply' }}><svg width="100%" height="100%"><filter id={`${fxId}-noise`}><feTurbulence type="fractalNoise" baseFrequency="0.65" numOctaves="3" stitchTiles="stitch" /><feColorMatrix type="saturate" values="0" /></filter><rect width="100%" height="100%" filter={`url(#${fxId}-noise)`} fill="transparent" /></svg></div>);
    return overlays;
  };

  const renderLayout = () => {
    const canvasPadding = `${padding}px`;
    const bRot = imageConfig?.boxRotation ?? 0;
    const bScale = imageConfig?.boxScale ?? 1;
    const bX = imageConfig?.boxX ?? 0;
    const bY = imageConfig?.boxY ?? 0;
    const boxWidth = imageConfig?.width || 480;
    const isFloatingBox = imageConfig?.type === 'IMAGE_BOX' || imageConfig?.type === 'IMAGE_GLASS_CARD';
    const imageBoxStyle: React.CSSProperties = {
      border: imageConfig?.borderWidth && isFloatingBox ? `${imageConfig.borderWidth}px solid ${imageConfig.borderColor || '#FFFFFF'}` : 'none',
      boxShadow: imageConfig?.hasShadow && isFloatingBox ? `0 ${imageConfig.hasTornEdges ? '30px 80px' : '40px 120px'} -20px rgba(0,0,0,${imageConfig.hasTornEdges ? '0.15' : '0.8'}), 0 0 100px ${imageConfig.borderColor || theme.colors.accent}${imageConfig.hasTornEdges ? '10' : '40'}` : 'none',
      transform: isFloatingBox ? `translate(${bX}px, ${bY}px) scale(${bScale}) rotate(${bRot}deg)` : undefined,
      transformOrigin: 'center',
      width: imageConfig?.type === 'IMAGE_BOX' ? `${boxWidth}px` : undefined,
      flexShrink: 0
    };
    const clarityIntensity = fx?.clarity || 0;
    const contentFilter = clarityIntensity > 0 ? `contrast(${1 + clarityIntensity * 0.25}) saturate(${1 + clarityIntensity * 0.15}) brightness(${1 - clarityIntensity * 0.05})` : 'none';

    const renderLayoutInternal = () => {
      if (templateDef.name === 'CARD_BOX' || templateDef.name === 'BENTO_SHOWCASE') {
        const boxBlocks = slide.blocks.filter(b => b.type === 'BOX');
        const otherBlocks = slide.blocks.filter(b => b.type !== 'BOX');
        return (<div className="relative h-full w-full flex flex-col justify-center items-center" style={{ padding: canvasPadding }}>{otherBlocks.length > 0 && (<div className="mb-12 w-full flex flex-col gap-8">{otherBlocks.map((b, i) => (<React.Fragment key={i}>{renderBlock(b, theme, onEditIcon, false, 0, slide.blocks.indexOf(b))}</React.Fragment>))}</div>)}<div className="grid grid-cols-2 gap-10 w-full">{boxBlocks.map((b, i) => (<React.Fragment key={i}>{renderBlock(b, theme, onEditIcon, true, i, slide.blocks.indexOf(b))}</React.Fragment>))}</div></div>);
      }
      if (imageConfig?.type === 'IMAGE_BOX') {
          const pos = imageConfig.position || 'right';
          const isHorizontal = pos === 'left' || pos === 'right';
          if (isHorizontal) {
            const isRight = pos === 'right';
            return (<div className={`relative h-full w-full flex items-center ${isRight ? 'flex-row' : 'flex-row-reverse'}`} style={{ padding: canvasPadding, gap: `${sectionGap}px` }}><div className="flex-1 min-w-0 z-20">{renderBlocks()}</div><div style={imageBoxStyle} className={`h-[850px] relative transition-all duration-300 z-10 bg-zinc-800 rounded-[50px] overflow-hidden border-4 border-white/10`}>{imageConfig.url ? (renderImage("w-full h-full", "cover")) : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><Box size={100} /></div>)}</div></div>);
          } else {
            const isBottom = pos === 'bottom';
            return (<div className={`relative h-full w-full flex flex-col items-center ${isBottom ? 'flex-col' : 'flex-col-reverse'}`} style={{ padding: canvasPadding, gap: `${sectionGap}px` }}><div className="flex-1 w-full flex flex-col justify-center z-20">{renderBlocks()}</div><div style={{ ...imageBoxStyle, height: '400px', width: '80%' }} className={`relative transition-all duration-300 z-10 bg-zinc-800 rounded-[50px] overflow-hidden border-4 border-white/10`}>{imageConfig.url ? (renderImage("w-full h-full", "cover")) : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><Box size={100} /></div>)}</div></div>);
          }
      }
      if (imageConfig?.type === 'IMAGE_GLASS_CARD' || templateDef.name === 'GLASS_OVERLAY' || templateDef.name === 'PREMIUM_GLASS') {
        const isDarkBox = imageConfig?.boxOverlay === 'dark';
        return (<div className="relative h-full w-full"><div className="absolute inset-0 overflow-hidden z-0 bg-zinc-900">{imageConfig?.url ? renderImage("w-full h-full", "cover") : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><ImageIcon size={100} /></div>)}</div><div className="relative z-10 h-full w-full flex flex-col justify-center items-center" style={{ padding: canvasPadding }}><div style={{ ...imageBoxStyle, width: '100%', maxWidth: '840px' }} className={`backdrop-blur-[20px] saturate-[160%] p-20 rounded-[80px] border border-white/30 transition-colors duration-500 ${isDarkBox ? 'bg-black/60' : 'bg-white/5'}`}>{renderBlocks()}</div></div></div>);
      }
      if (imageConfig?.type === 'IMAGE_SPLIT_HALF' || templateDef.name === 'ASPECT_EDITORIAL' || templateDef.name === 'SPLIT_EDITORIAL') {
        const pos = imageConfig?.position || 'right';
        const isSideBySide = pos === 'left' || pos === 'right';
        const isVertical = pos === 'top' || pos === 'bottom';
        const isRightOrBottom = pos === 'right' || pos === 'bottom';
        if (isSideBySide) return (<div className={`relative h-full w-full flex ${isRightOrBottom ? 'flex-row' : 'flex-row-reverse'}`} style={{ backgroundColor: theme.colors.background }}><div className="flex-1 h-full flex flex-col justify-center px-24 z-20 min-w-0">{renderBlocks()}</div><div className="flex-1 h-full relative overflow-hidden bg-zinc-900 border-x border-white/5 z-10 transition-all">{imageConfig?.url ? renderImage("w-full h-full", "cover", { transform: `translate(${bX}px, ${bY}px) scale(${bScale}) rotate(${bRot}deg)` }) : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><Layers size={100} /></div>)}</div></div>); 
        if (isVertical) return (<div className={`relative h-full w-full flex flex-col ${isRightOrBottom ? 'flex-col' : 'flex-col-reverse'}`} style={{ backgroundColor: theme.colors.background }}><div className="flex-1 w-full flex flex-col justify-center z-20" style={{ padding: canvasPadding }}><div className="max-w-[840px] mx-auto w-full">{renderBlocks()}</div></div><div className="w-full h-1/2 overflow-hidden relative border-y border-white/5 z-10 transition-all">{imageConfig?.url ? renderImage("w-full h-full", "cover", { transform: `translate(${bX}px, ${bY}px) scale(${bScale}) rotate(${bRot}deg)` }) : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><Layers size={100} /></div>)}</div></div>); 
      }
      if (imageConfig?.type === 'FOCUS_SUBJECT' || templateDef.name === 'PROFILE_FOCUS') {
        const isRight = (imageConfig?.position || 'right') === 'right';
        return (<div className="relative h-full w-full overflow-hidden flex"><div className="absolute inset-0 z-10 pointer-events-none overflow-hidden">{imageConfig?.url ? (<div className={`absolute bottom-0 h-full transition-all duration-300 ${isRight ? 'right-0' : 'left-0 scale-x-[-1]'}`} style={{ width: '70%', transform: `translate(${bX}px, ${bY}px) scale(${bScale}) rotate(${bRot}deg)`, transformOrigin: isRight ? 'bottom right' : 'bottom left', clipPath: imageConfig.hasTornEdges ? `url(#tornMask-${index})` : 'none' }}>{renderImage("w-full h-full", "contain")}</div>) : (<div className={`absolute bottom-0 h-[80%] w-1/2 border-4 border-dashed border-white/5 rounded-t-[200px] flex flex-col items-center justify-center text-white/10 ${isRight ? 'right-0' : 'left-0'}`}><User size={120} strokeWidth={1} /></div>)}</div><div className={`relative z-20 w-full h-full flex ${isRight ? 'justify-start' : 'justify-end'}`}><div className="w-1/2 h-full flex flex-col justify-center px-24">{renderBlocks()}</div></div></div>);
      }
      const isFullBg = imageConfig?.type === 'IMAGE_BACKGROUND' || imageConfig?.type === 'IMAGE_SELECT' || templateDef.name === 'MEGA_STATEMENT' || templateDef.name === 'CINEMATIC_BG' || templateDef.name === 'HERO_STATEMENT';
      const isSocialPost = templateDef.name === 'SOCIAL_CHECKLIST';
      return (<div className="relative h-full w-full overflow-hidden">{isFullBg && (<div className="absolute inset-0 overflow-hidden z-0 w-full h-full">{imageConfig?.url ? renderImage("w-full h-full", "cover", { transform: `translate(${bX}px, ${bY}px) scale(${bScale}) rotate(${bRot}deg)` }) : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><ImageIcon size={100}/></div>)}{imageConfig?.overlay === 'dark' && <div className="absolute inset-0 bg-black/60" />}</div>)}<div className="relative z-10 h-full w-full flex flex-col justify-center items-start" style={{ padding: canvasPadding }}><div className={`w-full max-w-[840px] mx-auto flex flex-col justify-center min-h-0 ${isSocialPost ? 'border border-white/10 rounded-[40px] p-16 bg-white/5' : ''}`}>{renderBlocks()}</div></div></div>);
    };
    return (<div style={{ filter: contentFilter }} className="h-full w-full overflow-hidden">{renderLayoutInternal()}</div>);
  };

  const customFontsCSS = useMemo(() => {
    if (!customFonts || customFonts.length === 0) return '';
    return customFonts.map(f => `@font-face { font-family: '${f.family}'; src: url('${f.url}'); font-display: swap; font-weight: normal; font-style: normal; }`).join('\n');
  }, [customFonts]);

  return (
    <div ref={canvasRef} style={{ backgroundColor: theme.colors.background, color: theme.colors.textPrimary, fontFamily: theme.typography.fontFamily }} className="relative w-[1080px] h-[1350px] flex flex-col shadow-2xl overflow-hidden shrink-0 select-auto">
      <style dangerouslySetInnerHTML={{ __html: customFontsCSS }} />
      {renderTornPaperSVG()}
      {renderLayout()}
      {renderFXOverlays()}
    </div>
  )
}

