                      <div className="space-y-3"><div className="text-brand text-[10px] font-black uppercase tracking-widest flex items-center gap-1.5"><UserCircle size={12}/>{p.client_name}</div><h3 className="text-lg font-black text-white truncate">{p.name}</h3><div className="flex gap-4 opacity-40 text-[9px] font-black uppercase"><span><Layers size={10} className="inline mr-1"/>{p.slideCount} slides</span><span><Clock size={10} className="inline mr-1"/>{new Date(p.updatedAt).toLocaleDateString()}</span></div></div>
