                           <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${currentSlide?.template === tpl.name ? 'bg-brand text-black shadow-lg shadow-brand/20' : 'bg-black text-zinc-600 group-hover:text-zinc-400'}`}><Library size={20}/></div>
                           <div className="flex-1 min-w-0"><p className={`text-[11px] font-black uppercase tracking-tight ${currentSlide?.template === tpl.name ? 'text-brand' : 'text-white'}`}>{tpl.name.replace(/_/g, ' ')}</p><p className="text-[9px] text-zinc-600 font-medium truncate">{tpl.description}</p></div>
