                 <button onClick={() => { setSelectedSlidesToExport(new Set(carousel?.slides.map((_,i)=>i))); setShowExportModal(true); }} className="w-full py-5 bg-brand text-black font-black rounded-2xl text-[10px] uppercase shadow-2xl flex items-center justify-center gap-3 transition-all hover:scale-[1.02] active:scale-95"><Download size={18} strokeWidth={3} /> Gerar Exportação</button>
              </footer>
           </aside>

           <main className="flex-1 bg-[#101012] relative flex flex-col items-center justify-center overflow-hidden">
              {error && <div className="absolute top-8 left-1/2 -translate-x-1/2 z-[100] bg-red-500/90 text-white px-8 py-4 rounded-3xl flex items-center gap-4 shadow-2xl backdrop-blur-xl animate-in slide-in-from-top-4"><AlertTriangle size={20} strokeWidth={3}/><span className="text-[11px] font-black uppercase tracking-widest">{error}</span></div>}

              <div className="absolute top-8 right-8 z-40 flex items-center gap-2 bg-black/40 backdrop-blur-2xl p-2 rounded-2xl border border-white/10 opacity-70 hover:opacity-100 transition-opacity"><button onClick={() => setZoom(Math.max(0.1, zoom-0.05))} className="p-2 text-zinc-500 hover:text-white transition-all"><ZoomOut size={18}/></button><div className="px-4 text-[10px] font-black font-mono text-zinc-400 bg-white/5 py-2 rounded-xl">{(zoom*100).toFixed(0)}%</div><button onClick={() => setZoom(Math.min(1.5, zoom+0.05))} className="p-2 text-zinc-500 hover:text-white transition-all"><ZoomIn size={18}/></button></div>

              <div className="flex-1 w-full flex items-center justify-center overflow-auto custom-scrollbar p-20" onMouseUp={e => {
                const s = window.getSelection(); if(!s || s.isCollapsed) return;
                const b = (e.target as HTMLElement).closest('[data-block-index]');
                if(b) {
                  const idx = parseInt(b.getAttribute('data-block-index') || '0');
                  setToolbarState({ blockIndex: idx, options: carousel?.slides[currentIndex]?.blocks[idx]?.options });
