              }}>
                <div style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }} className="transition-transform duration-500 shadow-[0_100px_250px_rgba(0,0,0,0.9)] shrink-0 rounded-[2px] overflow-hidden">
                  {carousel?.slides?.[currentIndex] ? (
