                  ) : <div className="w-[1080px] h-[1350px] bg-zinc-900 animate-pulse flex items-center justify-center"><Loader2 className="animate-spin text-brand" size={60} /></div>}
                </div>
              </div>

              {carousel && carousel.slides.length > 0 && (
                <div className="absolute bottom-10 left-1/2 -translate-x-1/2 z-40 flex items-center gap-10 bg-black/60 backdrop-blur-3xl px-12 py-5 rounded-full border border-white/10 shadow-2xl transition-all hover:border-white/20">
                   <button disabled={currentIndex === 0} onClick={() => setCurrentIndex(prev => prev - 1)} className="p-3 text-zinc-500 hover:text-brand disabled:opacity-5 transition-all"><ChevronLeft size={28} strokeWidth={3}/></button>
                   <div className="flex gap-3.5">
                      {carousel.slides.map((_, i) => (<button key={i} onClick={() => setCurrentIndex(i)} className={`h-2.5 transition-all duration-500 rounded-full ${currentIndex === i ? 'w-10 bg-brand shadow-lg shadow-brand/30' : 'w-2.5 bg-white/10 hover:bg-white/25'}`} />))}
                   </div>
                   <button disabled={currentIndex === carousel.slides.length - 1} onClick={() => setCurrentIndex(prev => prev + 1)} className="p-3 text-zinc-500 hover:text-brand disabled:opacity-5 transition-all"><ChevronRight size={28} strokeWidth={3}/></button>
                </div>
              )}
           </main>
        </div>
      )}
    </div>
  );
};

