        }
        target[path[path.length - 1]] = value;
        return JSON.stringify(parsed, null, 2);
      } catch (e) { return prev; }
    });
  }, []);

  const handleFontUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploadingFont(true);
    try {
      const sanitized = file.name.replace(/[^a-zA-Z0-9.]/g, '_');
      const fileName = `${Date.now()}_${sanitized}`;
      const { data, error } = await supabase.storage.from('fonts').upload(fileName, file);
      if (error) throw error;
      const { data: { publicUrl } } = supabase.storage.from('fonts').getPublicUrl(data.path);
      const newFont: CustomFont = { id: crypto.randomUUID(), name: file.name.split('.')[0], family: sanitized.split('.')[0], url: publicUrl };
      updateGlobalProperty(['customFonts'], [...(carousel?.customFonts || []), newFont]);
      showToast("Fonte sincronizada na nuvem!");
    } catch (err) {
      showToast("Erro no bucket 'fonts'. Certifique-se que ele é Público.", "error");
    } finally {
      setIsUploadingFont(false);
      if (fontInputRef.current) fontInputRef.current.value = '';
    }
  };

  const loadData = useCallback(() => {
    const local = JSON.parse(localStorage.getItem(STORAGE_KEYS.PROJECTS) || '[]');
    setProjects(local);
    // Tenta carregar paletas do Supabase
    supabase.from('brand_palettes').select('*').then(({ data }) => {
      if (data) setBrandPresets([...DEFAULT_BRAND_PRESETS, ...data]);
    });
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const handleSaveProject = () => {
    if (!saveFormData.name.trim()) return;
    const now = Date.now();
    const newProj: Project = {
      id: currentProjectId || crypto.randomUUID(),
      name: saveFormData.name,
      client_name: saveFormData.client || 'Geral',
      data: dslInput,
      slideCount: carousel?.slides.length || 0,
      updatedAt: now
    };
    const existing = JSON.parse(localStorage.getItem(STORAGE_KEYS.PROJECTS) || '[]');
    const idx = existing.findIndex((p: any) => p.id === newProj.id);
    let next;
    if (idx >= 0) { next = [...existing]; next[idx] = newProj; }
    else { next = [newProj, ...existing]; }
    localStorage.setItem(STORAGE_KEYS.PROJECTS, JSON.stringify(next));
    setCurrentProjectId(newProj.id);
    setShowSaveModal(false);
    showToast("Projeto salvo localmente!");
    loadData();
  };

  const handleOpenProject = (p: Project) => {
    setDslInput(p.data);
    setCurrentProjectId(p.id);
    setSaveFormData({ name: p.name, client: p.client_name });
    setCurrentIndex(0);
    setView('EDITOR');
  };

  const handleDeleteProject = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!window.confirm("Excluir projeto localmente?")) return;
    const existing = JSON.parse(localStorage.getItem(STORAGE_KEYS.PROJECTS) || '[]');
    const next = existing.filter((p: any) => p.id !== id);
    localStorage.setItem(STORAGE_KEYS.PROJECTS, JSON.stringify(next));
    showToast("Projeto excluído.");
    loadData();
  };

  useEffect(() => {
    try {
      const parsed = JSON.parse(dslInput);
      const res = carouselSchema.safeParse(parsed);
      if (res.success) { setCarousel(res.data); setError(null); }
      else { setError(res.error.issues[0].message); }
    } catch (e: any) { setError(e.message); }
  }, [dslInput]);

  const allFontOptions = useMemo(() => {
    const custom = (carousel?.customFonts || []).map(f => ({ id: f.family, label: `${f.name} (Custom)` }));
    return [...GOOGLE_FONTS, ...custom];
  }, [carousel?.customFonts]);

  const filteredProjects = projects.filter(p => p.name.toLowerCase().includes(searchQuery.toLowerCase()) || p.client_name.toLowerCase().includes(searchQuery.toLowerCase()));

  return (
    <div className="flex h-screen w-full bg-[#050507] text-zinc-300 font-sans overflow-hidden relative">
      {toast && (
        <div className={`fixed bottom-10 left-1/2 -translate-x-1/2 z-[9999] px-10 py-5 rounded-full flex items-center gap-4 animate-in slide-in-from-bottom-10 backdrop-blur-3xl border border-white/10 ${toast.type === 'success' ? 'bg-brand/90 text-black' : 'bg-red-500/90 text-white'}`}>
           {toast.type === 'success' ? <CheckCircle size={24} /> : <AlertCircle size={24} />}
           <span className="text-sm font-black uppercase tracking-widest">{toast.message}</span>
        </div>
      )}

      <input type="file" ref={fontInputRef} onChange={handleFontUpload} accept=".ttf,.otf,.woff2" className="hidden" />
      <input type="file" ref={importInputRef} onChange={(e) => {
        const f = e.target.files?.[0];
        if (f) {
          const r = new FileReader(); r.onload = (ev) => { setDslInput(ev.target?.result as string); setView('EDITOR'); showToast("Projeto Importado!"); }; r.readAsText(f);
        }
      }} className="hidden" />

      {showSaveModal && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 bg-black/90 backdrop-blur-xl animate-in fade-in" onClick={() => setShowSaveModal(false)}>
           <div className="w-full max-w-md bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8" onClick={e => e.stopPropagation()}>
              <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Salvar Localmente</h2>
              <div className="space-y-6">
                <div className="space-y-1"><label className="text-[10px] font-black uppercase text-zinc-500 px-1">Nome do Projeto</label><input type="text" value={saveFormData.name} onChange={e => setSaveFormData({...saveFormData, name: e.target.value})} className="w-full bg-black/40 border border-white/5 rounded-2xl p-4 text-white font-bold outline-none" /></div>
                <div className="space-y-1"><label className="text-[10px] font-black uppercase text-zinc-500 px-1">Cliente</label><input type="text" value={saveFormData.client} onChange={e => setSaveFormData({...saveFormData, client: e.target.value})} className="w-full bg-black/40 border border-white/5 rounded-2xl p-4 text-white font-bold outline-none" /></div>
              </div>
              <button onClick={handleSaveProject} className="w-full py-5 bg-brand text-black font-black uppercase rounded-2xl shadow-xl flex items-center justify-center gap-3"><Save size={20} /> Salvar no Navegador</button>
           </div>
        </div>
      )}

      {view === 'DASHBOARD' ? (
        <div className="flex-1 flex flex-col overflow-y-auto custom-scrollbar">
           <header className="px-10 py-10 flex items-center justify-between sticky top-0 bg-[#050507]/90 backdrop-blur-xl z-50">
              <div className="flex items-center gap-6"><img src={LOGO_URL} className="h-12" /><div className="bg-zinc-800 px-4 py-1.5 rounded-full text-[9px] font-black uppercase text-zinc-500 flex items-center gap-2"><Monitor size={10} /> Local Storage Mode</div></div>
              <div className="flex-1 max-w-xl mx-20 relative"><Search className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-600" size={18} /><input type="text" placeholder="Pesquisar projetos locais..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-sm font-bold outline-none" /></div>
              <div className="flex gap-4"><button onClick={() => importInputRef.current?.click()} className="px-8 py-4 bg-white/5 border border-white/10 rounded-2xl text-[11px] font-black uppercase hover:bg-white/10">JSON Import</button><button onClick={() => { setDslInput(INITIAL_DSL); setCurrentProjectId(null); setView('EDITOR'); }} className="px-8 py-4 bg-brand text-black rounded-2xl text-[11px] font-black uppercase shadow-xl">+ Novo Projeto</button></div>
           </header>
           <main className="p-10 max-w-[1600px] mx-auto w-full grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {filteredProjects.map(p => (
                <div key={p.id} onClick={() => handleOpenProject(p)} className="h-80 bg-zinc-900/40 border border-white/5 rounded-[40px] p-8 flex flex-col justify-between group cursor-pointer hover:border-brand/40">
                   <div className="flex justify-between items-start"><div className="w-14 h-14 bg-black/40 rounded-2xl flex items-center justify-center border border-white/5"><Library className="text-zinc-600 group-hover:text-brand" /></div><button onClick={e => handleDeleteProject(p.id, e)} className="p-2 text-zinc-700 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={18}/></button></div>
                   <div className="space-y-3"><div className="text-brand text-[10px] font-black uppercase tracking-widest">{p.client_name}</div><h3 className="text-lg font-black text-white truncate">{p.name}</h3><div className="flex gap-4 opacity-40 text-[9px] font-black uppercase"><span>{p.slideCount} slides</span><span>{new Date(p.updatedAt).toLocaleDateString()}</span></div></div>
                </div>
              ))}
           </main>
        </div>
      ) : (
        <div className="flex h-screen w-full">
           <aside className="w-[440px] bg-zinc-900/50 backdrop-blur-3xl border-r border-white/5 flex flex-col shrink-0 z-20">
              <header className="p-6 border-b border-white/5 flex flex-col gap-6">
                 <div className="flex items-center justify-between"><button onClick={() => setView('DASHBOARD')} className="p-2.5 bg-white/5 hover:bg-white/10 rounded-xl text-zinc-500"><Home size={20} /></button><img src={LOGO_URL} className="h-8" /><button onClick={() => setShowSaveModal(true)} className="p-2.5 bg-brand/10 hover:bg-brand/20 text-brand rounded-xl transition-all"><Save size={20} /></button></div>
                 <nav className="flex p-1 bg-black/40 rounded-2xl overflow-x-auto no-scrollbar">
                    {[
                      { id: 'TEMPLATES', icon: Library, label: 'Tpl' },
                      { id: 'BLOCKS', icon: TypeIcon, label: 'Content' },
                      { id: 'DESIGN', icon: Palette, label: 'Design' },
                      { id: 'FX', icon: Sparkles, label: 'FX' },
                      { id: 'ASSETS', icon: ImageIcon, label: 'Assets' },
                      { id: 'JSON', icon: FileJson, label: 'Raw' },
                    ].map(t => (<button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`flex-1 py-3 px-2 flex flex-col items-center gap-1 rounded-xl transition-all ${activeTab === t.id ? 'bg-zinc-800 text-brand border border-white/5 shadow-xl' : 'text-zinc-500 hover:text-white'}`}><t.icon size={16}/><span className="text-[8px] font-black uppercase tracking-tighter">{t.label}</span></button>))}
                 </nav>
              </header>
              <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-10">
                 {activeTab === 'FX' ? (
                   <div className="space-y-10 animate-in slide-in-from-left-4 duration-300">
                      <div className="p-4 bg-brand/5 border border-brand/10 rounded-2xl flex items-center gap-3"><Sparkles size={20} className="text-brand shrink-0" /><p className="text-[10px] font-medium text-brand/60 leading-relaxed uppercase tracking-widest">Efeitos aplicados globalmente a todos os slides.</p></div>
                      <section className="space-y-8">
                         <div className="space-y-6">
                            <div className="flex items-center gap-2 px-1"><Wind size={14} className="text-zinc-600" /><h3 className="text-[10px] font-black text-white uppercase tracking-widest">Granulação (Noise)</h3></div>
                            <div className="space-y-6">
                               <TransformControl label="Intensidade" value={currentSlide?.options?.postFX?.noiseAmount ?? 0} min={0} max={0.3} step={0.01} onChange={v => updateGlobalFX('noiseAmount', v)} />
                               <div className="space-y-2"><span className="text-[9px] font-black text-zinc-500 uppercase px-1">Modo de Mistura</span><div className="grid grid-cols-2 gap-1.5">{['multiply', 'overlay', 'soft-light', 'screen'].map(m => (<button key={m} onClick={() => updateGlobalFX('noiseMode', m)} className={`py-2 px-3 rounded-lg text-[9px] font-black uppercase tracking-tighter border transition-all ${currentSlide?.options?.postFX?.noiseMode === m ? 'bg-brand text-black border-brand' : 'bg-black/40 border-white/5 text-zinc-500'}`}>{m}</button>))}</div></div>
                            </div>
                         </div>
                         <div className="space-y-6 pt-6 border-t border-white/5"><div className="flex items-center gap-2 px-1"><Contrast size={14} className="text-zinc-600" /><h3 className="text-[10px] font-black text-white uppercase tracking-widest">Clarity & Contraste</h3></div><TransformControl label="Nível" value={currentSlide?.options?.postFX?.clarity ?? 0} min={0} max={1} step={0.01} onChange={v => updateGlobalFX('clarity', v)} /></div>
                         <div className="space-y-6 pt-6 border-t border-white/5"><div className="flex items-center gap-2 px-1"><Sun size={14} className="text-zinc-600" /><h3 className="text-[10px] font-black text-white uppercase tracking-widest">Luz Ambiente</h3></div><TransformControl label="Intensidade" value={currentSlide?.options?.postFX?.lightingIntensity ?? 0} min={0} max={1} step={0.01} onChange={v => updateGlobalFX('lightingIntensity', v)} /></div>
                         <div className="space-y-6 pt-6 border-t border-white/5"><div className="flex items-center gap-2 px-1"><Focus size={14} className="text-zinc-600" /><h3 className="text-[10px] font-black text-white uppercase tracking-widest">Vinheta</h3></div><TransformControl label="Nível" value={currentSlide?.options?.postFX?.vignette ?? 0} min={0} max={1} step={0.01} onChange={v => updateGlobalFX('vignette', v)} /></div>
                      </section>
                   </div>
                 ) : activeTab === 'DESIGN' ? (
                   <div className="space-y-10">
                      <section className="space-y-4 pt-6"><div className="flex items-center justify-between px-1"><div className="flex items-center gap-2"><CloudUpload size={16} className="text-brand" /><h3 className="text-[10px] font-black text-white uppercase tracking-widest">Cloud Fonts</h3></div></div><button onClick={() => fontInputRef.current?.click()} disabled={isUploadingFont} className="w-full py-8 border-2 border-dashed border-white/5 rounded-3xl flex flex-col items-center justify-center gap-3 text-zinc-600 hover:text-brand hover:bg-brand/5 transition-all">{isUploadingFont ? <Loader2 className="animate-spin" /> : <HardDrive size={28} />}<div className="text-center"><p className="text-[10px] font-black uppercase">Subir Fonte (.ttf/.otf)</p></div></button></section>
                      <section className="space-y-6 pt-6 border-t border-white/5">
                         <div className="space-y-4">
                            <div className="space-y-2"><label className="text-[9px] font-black uppercase text-zinc-500">Fonte Padrão</label><select value={currentSlide?.options?.fontPadrão || 'Inter'} onChange={e => updateSlideProperty(['options', 'fontPadrão'], e.target.value)} className="w-full bg-black/40 border border-white/5 rounded-xl py-3 px-3 text-xs font-bold text-white outline-none">{allFontOptions.map(f => <option key={f.id} value={f.id}>{f.label}</option>)}</select></div>
                            <div className="space-y-2"><label className="text-[9px] font-black uppercase text-zinc-500">Fonte Destaque</label><select value={currentSlide?.options?.fontDestaque || 'Instrument Serif'} onChange={e => updateSlideProperty(['options', 'fontDestaque'], e.target.value)} className="w-full bg-black/40 border border-white/5 rounded-xl py-3 px-3 text-xs font-bold text-white outline-none">{allFontOptions.map(f => <option key={f.id} value={f.id}>{f.label}</option>)}</select></div>
                         </div>
                      </section>
                      <TransformControl label="Padding Global" value={currentSlide?.options?.padding ?? 80} min={20} max={200} step={4} onChange={v => updateSlideProperty(['options', 'padding'], v)} />
                      <TransformControl label="Gap Global" value={currentSlide?.options?.blockGap ?? 16} min={0} max={160} step={2} onChange={v => updateSlideProperty(['options', 'blockGap'], v)} />
                   </div>
                 ) : activeTab === 'BLOCKS' ? (
                   <div className="space-y-4 animate-in slide-in-from-left-4 duration-300">
                      {currentSlide?.blocks.map((b, idx) => (
                        <div key={idx} className="bg-white/5 border border-white/5 rounded-3xl overflow-hidden group">
                           <div className="px-5 py-3 bg-black/20 flex items-center justify-between border-b border-white/5"><span className="text-[9px] font-black uppercase text-zinc-500">{b.type}</span><button onClick={() => { const next = [...currentSlide.blocks]; next.splice(idx, 1); updateSlideProperty(['blocks'], next); }} className="p-1 text-zinc-700 hover:text-red-400"><Trash2 size={12}/></button></div>
                           <div className="p-5 space-y-4">
                              <textarea value={b.content as any} onChange={e => updateSlideProperty(['blocks', idx, 'content'], b.type === 'LIST' ? e.target.value.split('\n') : e.target.value)} className="w-full bg-black/40 border border-white/5 rounded-2xl p-4 text-xs font-bold text-white outline-none min-h-[120px] resize-none" placeholder="Conteúdo..." />
                              <div className="grid grid-cols-2 gap-4">
                                 <select value={b.options?.fontVariant || 'padrão'} onChange={e => updateSlideProperty(['blocks', idx, 'options', 'fontVariant'], e.target.value)} className="w-full bg-black/40 border border-white/5 rounded-xl py-2 px-3 text-[10px] font-black uppercase text-zinc-400"><option value="padrão">Padrão</option><option value="destaque">Destaque</option></select>
                                 <TransformControl label="FontSize" value={b.options?.fontSize || 32} min={10} max={300} step={1} onChange={v => updateSlideProperty(['blocks', idx, 'options', 'fontSize'], v)} />
                              </div>
                           </div>
                        </div>
                      ))}
                      <button onClick={() => { const n = [...currentSlide!.blocks, { type: 'PARAGRAPH', content: 'Novo conteúdo...', options: { fontSize: 32 } }]; updateSlideProperty(['blocks'], n); }} className="w-full py-8 border-2 border-dashed border-white/5 rounded-[40px] flex flex-col items-center justify-center gap-2 text-zinc-600 hover:text-brand transition-all"><Plus size={24}/><span className="text-[10px] font-black uppercase">Adicionar Bloco</span></button>
                   </div>
                 ) : activeTab === 'ASSETS' ? (
                   <div className="space-y-8">
                      <div className="relative aspect-[4/5] rounded-[40px] overflow-hidden bg-zinc-950 border-2 border-dashed border-white/5 flex flex-col items-center justify-center text-center p-10 group cursor-pointer">
                         {currentSlide?.image?.url ? (<img src={currentSlide.image.url} className="absolute inset-0 w-full h-full object-cover" />) : (<div className="space-y-4 text-zinc-700"><ImageIcon size={64} /><p className="text-[10px] font-black uppercase">Sem Imagem</p></div>)}
                         <input type="file" onChange={e => { const f = e.target.files?.[0]; if(f) { const r = new FileReader(); r.onload = (ev) => updateSlideProperty(['image', 'url'], ev.target?.result); r.readAsDataURL(f); } }} className="absolute inset-0 opacity-0 cursor-pointer" />
                         {currentSlide?.image?.url && <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center"><button onClick={() => updateSlideProperty(['image', 'url'], null)} className="p-4 bg-red-500 text-white rounded-2xl"><Trash2 size={24}/></button></div>}
                      </div>
                      {currentSlide?.image?.url && (
                        <div className="space-y-6">
                           <div className="grid grid-cols-5 gap-2.5">{IMAGE_TYPE_PRESETS.map(p => (<button key={p.id} onClick={() => updateSlideProperty(['image', 'type'], p.id)} className={`p-3 rounded-xl border flex items-center justify-center transition-all ${currentSlide?.image?.type === p.id ? 'bg-brand text-black border-brand shadow-lg' : 'bg-black/40 border-white/5 text-zinc-500'}`}><p.icon size={18}/></button>))}</div>
                           <TransformControl label="Zoom" value={currentSlide?.image?.boxScale || 1} min={0.5} max={4} step={0.05} onChange={v => updateSlideProperty(['image', 'boxScale'], v)} />
                           <div className="grid grid-cols-2 gap-4"><TransformControl label="X Pos" value={currentSlide?.image?.boxX || 0} min={-600} max={600} step={1} onChange={v => updateSlideProperty(['image', 'boxX'], v)} /><TransformControl label="Y Pos" value={currentSlide?.image?.boxY || 0} min={-800} max={800} step={1} onChange={v => updateSlideProperty(['image', 'boxY'], v)} /></div>
                        </div>
                      )}
                   </div>
                 ) : activeTab === 'TEMPLATES' ? (
                    <div className="grid grid-cols-1 gap-2.5 animate-in slide-in-from-left-4 duration-300">
                       {templates.map(tpl => (
                         <button key={tpl.name} onClick={() => updateSlideProperty(['template'], tpl.name)} className={`w-full p-5 border rounded-[32px] flex items-center gap-5 transition-all text-left group ${currentSlide?.template === tpl.name ? 'bg-brand/10 border-brand shadow-xl' : 'bg-white/5 border-white/5 hover:border-white/10'}`}>
                            <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${currentSlide?.template === tpl.name ? 'bg-brand text-black' : 'bg-black text-zinc-600'}`}><Library size={20}/></div>
                            <div className="flex-1 min-w-0"><p className={`text-[11px] font-black uppercase tracking-tight ${currentSlide?.template === tpl.name ? 'text-brand' : 'text-white'}`}>{tpl.name.replace(/_/g, ' ')}</p><p className="text-[9px] text-zinc-600 truncate">{tpl.description}</p></div>
                         </button>
                       ))}
                    </div>
                 ) : activeTab === 'JSON' ? (
                    <textarea value={dslInput} onChange={e => setDslInput(e.target.value)} className="w-full h-[600px] bg-black/60 border border-white/5 rounded-[40px] p-6 text-[10px] font-mono outline-none" spellCheck={false} />
                 ) : null}
              </div>
              <footer className="p-6 border-t border-white/5 bg-zinc-950/80 backdrop-blur-md">
                 <button onClick={() => { setSelectedSlidesToExport(new Set(carousel?.slides.map((_,i)=>i))); setShowExportModal(true); }} className="w-full py-5 bg-brand text-black font-black rounded-2xl text-[10px] uppercase shadow-2xl flex items-center justify-center gap-3 active:scale-95"><Download size={18} strokeWidth={3} /> Gerar Exportação</button>
              </footer>
           </aside>
           <main className="flex-1 bg-[#101012] relative flex flex-col items-center justify-center overflow-hidden">
              {error && <div className="absolute top-8 left-1/2 -translate-x-1/2 z-[100] bg-red-500/90 text-white px-8 py-4 rounded-3xl flex items-center gap-4 shadow-2xl backdrop-blur-xl animate-in slide-in-from-top-4"><AlertTriangle size={20} strokeWidth={3}/><span className="text-[11px] font-black uppercase tracking-widest">{error}</span></div>}
              <div className="absolute top-8 right-8 z-40 flex items-center gap-2 bg-black/40 backdrop-blur-2xl p-2 rounded-2xl border border-white/10 opacity-70 hover:opacity-100 transition-opacity"><button onClick={() => setZoom(Math.max(0.1, zoom-0.05))} className="p-2 text-zinc-500 hover:text-white transition-all"><ZoomOut size={18}/></button><div className="px-4 text-[10px] font-black font-mono text-zinc-400 bg-white/5 py-2 rounded-xl">{(zoom*100).toFixed(0)}%</div><button onClick={() => setZoom(Math.min(1.5, zoom+0.05))} className="p-2 text-zinc-500 hover:text-white transition-all"><ZoomIn size={18}/></button></div>
              <div className="flex-1 w-full flex items-center justify-center overflow-auto custom-scrollbar p-20">
                <div style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }} className="shadow-[0_100px_250px_rgba(0,0,0,0.9)] shrink-0 rounded-[2px] overflow-hidden">
                  {carousel?.slides?.[currentIndex] ? (
                    <SlideCanvas slide={carousel.slides[currentIndex]} index={currentIndex} canvasRef={canvasRef} customFonts={carousel.customFonts} />
                  ) : <div className="w-[1080px] h-[1350px] bg-zinc-900 animate-pulse flex items-center justify-center"><Loader2 className="animate-spin text-brand" size={60} /></div>}
                </div>
              </div>
              {carousel && carousel.slides.length > 0 && (
                <div className="absolute bottom-10 left-1/2 -translate-x-1/2 z-40 flex items-center gap-10 bg-black/60 backdrop-blur-3xl px-12 py-5 rounded-full border border-white/10 shadow-2xl transition-all hover:border-white/20">
                   <button disabled={currentIndex === 0} onClick={() => setCurrentIndex(prev => prev - 1)} className="p-3 text-zinc-500 hover:text-brand disabled:opacity-5 transition-all"><ChevronLeft size={28} strokeWidth={3}/></button>
                   <div className="flex gap-3.5">{carousel.slides.map((_, i) => (<button key={i} onClick={() => setCurrentIndex(i)} className={`h-2.5 transition-all duration-500 rounded-full ${currentIndex === i ? 'w-10 bg-brand shadow-lg shadow-brand/30' : 'w-2.5 bg-white/10 hover:bg-white/25'}`} />))}</div>
                   <button disabled={currentIndex === carousel.slides.length - 1} onClick={() => setCurrentIndex(prev => prev + 1)} className="p-3 text-zinc-500 hover:text-brand disabled:opacity-5 transition-all"><ChevronRight size={28} strokeWidth={3}/></button>
                </div>
              )}
           </main>
        </div>
      )}
    </div>
  );
};

export default App;
